#[panic_handler]
fn panic(info: &PanicInfo) -> ! {
    crate::println!("[panic] {}", info);
    loop {}
}

#[alloc_error_handler]
fn alloc_error_handler(layout: core::alloc::Layout) -> ! {
    crate::println!(
        "[alloc] allocation error: size={}, align={}",
        layout.size(),
        layout.align(),
    );

    panic!(
