#[macro_export]
macro_rules! print {
    ($($arg:tt)*) => {
        $crate::drivers::serial::_print(format_args!($($arg)*));
    };
}

#[macro_export]
macro_rules! println {
    () => {
        $crate::print!("\n");
    };
    ($fmt:expr) => {
        $crate::print!(concat!($fmt, "\n"));
    };
    ($fmt:expr, $($arg:tt)*) => {
        $crate::print!(concat!($fmt, "\n"), $($arg)*);
    };
}

#[macro_export]
macro_rules! kprint {
    ($($arg:tt)*) => {
        #[cfg(feature = "kernel_log")]
        {
            $crate::print!($($arg)*);
        }
    };
}

#[macro_export]
macro_rules! kprintln {
    () => {
        #[cfg(feature = "kernel_log")]
        {
            $crate::println!();
        }
    };
    ($($arg:tt)*) => {
        #[cfg(feature = "kernel_log")]
        {
            $crate::println!($($arg)*);
        }
    };
}

