ENTRY(_start)

BASE_ADDRESS = 0x80200000;
KERNEL_HEAP_SIZE = 0x200000;

SECTIONS
{
    . = BASE_ADDRESS;

    skernel = .;

    .text : ALIGN(4K) {
        stext = .;
        *(.text.entry)
        *(.text .text.*)
        etext = .;
    }

    .rodata : ALIGN(4K) {
        srodata = .;
        *(.rodata .rodata.*)
        *(.srodata .srodata.*)
        erodata = .;
    }

    .data : ALIGN(4K) {
        sdata = .;
        *(.data .data.*)
        *(.sdata .sdata.*)
        edata = .;
    }

    .bss : ALIGN(4K) {
        sbss = .;
        *(.bss.stack)
        *(.sbss .sbss.*)
        *(.bss .bss.*)
        *(COMMON)
        ebss = .;
    }

    . = ALIGN(4K);
    skernel_heap = .;
    . += KERNEL_HEAP_SIZE;
    ekernel_heap = .;

    . = ALIGN(4K);
    ekernel = .;
}

OUTPUT_ARCH(loongarch64)
ENTRY(_start)

PHY_BASE_ADDRESS = 0x200000;
VIRT_OFFSET = 0x9000000000000000;
BASE_ADDRESS = PHY_BASE_ADDRESS + VIRT_OFFSET;
KERNEL_HEAP_SIZE = 0x200000;

SECTIONS
{
    . = PHY_BASE_ADDRESS;
    .text.entry : ALIGN(4K) {
        stext = .;
        *(.text.entry)
    }

    . = ALIGN(4K);
    . += VIRT_OFFSET;
    skernel = .;

    .text : AT(ADDR(.text) - VIRT_OFFSET) {
        *(.text .text.*)
        etext = .;
    }

    .rodata : AT(ADDR(.rodata) - VIRT_OFFSET) {
        srodata = .;
        *(.rodata .rodata.*)
        *(.srodata .srodata.*)
        erodata = .;
    }

    .data : AT(ADDR(.data) - VIRT_OFFSET) {
        sdata = .;
        *(.data .data.*)
        *(.sdata .sdata.*)
        edata = .;
    }

    .bss : AT(ADDR(.bss) - VIRT_OFFSET) {
        sbss = .;
        *(.bss.stack)
        *(.sbss .sbss.*)
        *(.bss .bss.*)
        *(COMMON)
        ebss = .;
    }

    . = ALIGN(4K);
    skernel_heap = .;
    . += KERNEL_HEAP_SIZE;
    ekernel_heap = .;

    . = ALIGN(4K);
    ekernel = .;

    /DISCARD/ : {
        *(.eh_frame)
        *(.debug*)
    }
}

