pub fn shutdown() -> ! {
    // Try SBI v0.2+ SRST extension first
    const SBI_EXT_SRST: usize = 0x5352_5354;
    unsafe {
        core::arch::asm!(
            "ecall",
            in("a0") 0usize,  // RESET_TYPE_SHUTDOWN
            in("a1") 0usize,  // RESET_REASON_NO_REASON
            in("a6") 0usize,  // SBI_FUNC_SYSTEM_RESET
            in("a7") SBI_EXT_SRST,
            lateout("a0") _,
            lateout("a1") _,
            options(nostack)
        );
    }

    // Fallback: legacy SBI v0.1 shutdown
    unsafe {
        core::arch::asm!(
            "ecall",
            in("a7") 0x08usize,  // SBI_EXT_0_1_SHUTDOWN
            options(nostack)
        );
    }

    // Last resort: halt
    crate::kprintln!("[shutdown] SBI shutdown failed, halting");
    crate::drivers::serial::Serial::putchar(b'\n');
    loop {
        unsafe {
            core::arch::asm!("wfi", options(nomem, nostack));
        }
    }
}

pub fn is_timer_interrupt(scause: usize) -> bool {
    let interrupt_bit = 1usize << (usize::BITS as usize - 1);
    scause == (interrupt_bit | 5)
}

use alloc::vec::Vec;
use core::arch::asm;

use crate::mm::address::{PhysAddr, PhysPageNum, VirtPageNum};
use crate::mm::frame_allocator::{frame_alloc, frame_dealloc, zero_frame};
use crate::mm::page_table::{MapPermission, PageTable};

const PTE_V: usize = 1 << 0;
const PTE_R: usize = 1 << 1;
const PTE_W: usize = 1 << 2;
const PTE_X: usize = 1 << 3;
const PTE_U: usize = 1 << 4;
const PTE_A: usize = 1 << 6;
const PTE_D: usize = 1 << 7;

const SATP_MODE_SV39: usize = 8usize << 60;

#[derive(Copy, Clone)]
#[repr(transparent)]
pub struct RiscvPte(pub usize);

impl RiscvPte {
    pub fn empty() -> Self {
        Self(0)
    }

    pub fn is_valid(&self) -> bool {
        self.0 & PTE_V != 0
    }

    pub fn ppn(&self) -> PhysPageNum {
        PhysPageNum(self.0 >> 10)
    }

    pub fn new(ppn: PhysPageNum, flags: usize) -> Self {
        Self((ppn.0 << 10) | flags)
    }
}

pub struct RiscvPageTable {
    root_ppn: PhysPageNum,
    frames: Vec<PhysPageNum>,
}

impl RiscvPageTable {
    fn pte_array(ppn: PhysPageNum) -> &'static mut [RiscvPte; 512] {
        let pa: PhysAddr = ppn.into();
        unsafe { &mut *(pa.0 as *mut [RiscvPte; 512]) }
    }

    fn vpn_indexes(vpn: VirtPageNum) -> [usize; 3] {
        let vpn = vpn.0;
        [vpn & 0x1ff, (vpn >> 9) & 0x1ff, (vpn >> 18) & 0x1ff]
    }

    fn flags_from_perm(perm: MapPermission) -> usize {
        let mut flags = PTE_V | PTE_A | PTE_D;

        if perm.read {
            flags |= PTE_R;
        }
        if perm.write {
            flags |= PTE_W;
        }
        if perm.execute {
            flags |= PTE_X;
        }
        if perm.user {
            flags |= PTE_U;
        }

        flags
    }

    fn find_pte_create(&mut self, vpn: VirtPageNum) -> &'static mut RiscvPte {
        let indexes = Self::vpn_indexes(vpn);
        let mut ppn = self.root_ppn;

        for level in (1..=2).rev() {
            let pte_array = Self::pte_array(ppn);
            let pte = &mut pte_array[indexes[level]];

            if !pte.is_valid() {
                let new_ppn = frame_alloc().expect("failed to allocate page table frame");
                zero_frame(new_ppn);
                self.frames.push(new_ppn);
                *pte = RiscvPte::new(new_ppn, PTE_V);
            }

            ppn = pte.ppn();
        }

        let pte_array = Self::pte_array(ppn);
        &mut pte_array[indexes[0]]
    }

    fn find_pte(&self, vpn: VirtPageNum) -> Option<&'static mut RiscvPte> {
        let indexes = Self::vpn_indexes(vpn);
        let mut ppn = self.root_ppn;

        for level in (1..=2).rev() {
            let pte_array = Self::pte_array(ppn);
            let pte = &mut pte_array[indexes[level]];

            if !pte.is_valid() {
                return None;
            }

            ppn = pte.ppn();
        }

        let pte_array = Self::pte_array(ppn);
        Some(&mut pte_array[indexes[0]])
    }
}

impl PageTable for RiscvPageTable {
    fn new() -> Self {
        // crate::println!("[riscv64 mm] page table new begin");

        let root_ppn = frame_alloc().expect("failed to allocate root page table");

        crate::kprintln!(
            "[riscv64 mm] root page table frame allocated: ppn={:#x}, pa={:#x}",
            root_ppn.0,
            root_ppn.0 << 12
        );

        // crate::println!("[riscv64 mm] heap before zero_frame");
        // crate::mm::heap_allocator::dump_heap_free_list();

        zero_frame(root_ppn);

        // crate::println!("[riscv64 mm] root page table frame zeroed");

        // crate::println!("[riscv64 mm] heap after zero_frame");
        // crate::mm::heap_allocator::dump_heap_free_list();

        let mut frames = Vec::new();

        // crate::println!(
        //     "[riscv64 mm] frames vec created: len={}, cap={}",
        //     frames.len(),
        //     frames.capacity()
        // );

        // crate::println!("[riscv64 mm] frames push root begin");

        frames.push(root_ppn);

        // crate::println!(
        //     "[riscv64 mm] frames push root done: len={}, cap={}",
        //     frames.len(),
        //     frames.capacity()
        // );

        Self { root_ppn, frames }
    }

    fn map(&mut self, vpn: VirtPageNum, ppn: PhysPageNum, perm: MapPermission) {
        let pte = self.find_pte_create(vpn);

        // Allow overwriting user pages (for MAP_FIXED, mprotect, COW)
        if pte.is_valid() && perm.user {
            let flags = Self::flags_from_perm(perm);
            *pte = RiscvPte::new(ppn, flags);
            unsafe { core::arch::asm!("sfence.vma zero, zero"); }
            return;
        }

        if pte.is_valid() {
            panic!("vpn {:#x} is already mapped", vpn.0);
        }

        let flags = Self::flags_from_perm(perm);
        *pte = RiscvPte::new(ppn, flags);
    }

    fn unmap(&mut self, vpn: VirtPageNum) {
        let pte = self.find_pte(vpn).expect("vpn is not mapped");
        *pte = RiscvPte::empty();
    }

    fn translate(&self, vpn: VirtPageNum) -> Option<PhysPageNum> {
        let pte = self.find_pte(vpn)?;

        if pte.is_valid() {
            Some(pte.ppn())
        } else {
            None
        }
    }

    fn token(&self) -> usize {
        SATP_MODE_SV39 | self.root_ppn.0
    }
}

impl Drop for RiscvPageTable {
    fn drop(&mut self) {
        let count = self.frames.len();

        for ppn in self.frames.drain(..) {
            frame_dealloc(ppn);
        }

        if count > 0 {
            crate::kprintln!("[mm] drop page table frames={}", count);
        }
    }
}

