const CSR_ECFG: usize = 0x4;
const CSR_EENTRY: usize = 0xc;
const CSR_TCFG: usize = 0x41;
const CSR_TICLR: usize = 0x44;
const ESTAT_ECODE_SHIFT: usize = 16;
const ESTAT_ECODE_MASK: usize = 0x3f;
const PRMD_PPLV_MASK: usize = 0x3;
const CRMD_IE: usize = 1 << 2;
const ECFG_TIMER: usize = 1 << 11;
const TICLR_CLEAR_TIMER: usize = 1;
const VIRT_OFFSET: usize = 0x9000_0000_0000_0000;
const ECODE_SYSCALL: usize = 11;
const TIMER_TICKS_PER_SEC: usize = 100;

