#[unsafe(no_mangle)]
pub extern "C" fn loongarch64_kernel_trap_handler(cx: &mut crate::trap::context::TrapContext) {
    let ecode = (cx.estat >> ESTAT_ECODE_SHIFT) & ESTAT_ECODE_MASK;
    let from_user = (cx.prmd & PRMD_PPLV_MASK) == 3;

    if from_user && ecode == ECODE_SYSCALL {
        let syscall_id = cx.x[11];
        let args = [cx.x[4], cx.x[5], cx.x[6], cx.x[7], cx.x[8], cx.x[9]];
        crate::kprintln!(
            "[syscall-la] id={}, args=[{:#x}, {:#x}, {:#x}]",
            syscall_id,
            args[0],
            args[1],
            args[2]
        );

        if syscall_id == crate::syscall::SYS_YIELD {
            cx.x[4] = 0;
            cx.era += 4;
            let ret = crate::syscall::syscall(syscall_id, args);
            cx.x[4] = ret as usize;
            return;
        }

        let ret = crate::syscall::syscall(syscall_id, args);

        if syscall_id == crate::syscall::SYS_EXECVE && ret == 0 {
            crate::kprintln!("[syscall-la] execve success");
            return;
        }

        cx.x[4] = ret as usize;
        cx.era += 4;
        return;
    }

    crate::println!(
        "[la-trap] {} trap: ecode={}, era={:#x}, badv={:#x}",
        if from_user { "user" } else { "kernel" },
        ecode,
        cx.era,
        cx.badv
    );

    if from_user {
        crate::println!("[la-trap] user exception ecode={}, killing process", ecode);
        crate::println!("[la-trap] regs: a0={:#x} a1={:#x} a2={:#x} sp={:#x} ra={:#x} tp={:#x}",
            cx.x[4], cx.x[5], cx.x[6], cx.x[3], cx.x[1], cx.x[2]);
        crate::println!("[la-trap] regs: a3={:#x} a4={:#x} a5={:#x} a6={:#x} a7={:#x}",
            cx.x[7], cx.x[8], cx.x[9], cx.x[10], cx.x[11]);
        crate::println!("[la-trap] regs: t0-t4: {:#x} {:#x} {:#x} {:#x} {:#x}",
            cx.x[12], cx.x[13], cx.x[14], cx.x[15], cx.x[16]);
        crate::println!("[la-trap] regs: s0-s4: {:#x} {:#x} {:#x} {:#x} {:#x}",
            cx.x[23], cx.x[24], cx.x[25], cx.x[26], cx.x[27]);
        crate::println!("[la-trap] regs: fp={:#x} gp={:#x}",
            cx.x[22], cx.x[21]);
        // Kill the faulting process instead of shutting down the kernel
        crate::task::exit_current(-1);
    } else {
        cx.era += 4;
    }
}

static mut CTX_BOUNCE_STACK: [u8; 4096] = [0; 4096];
static mut CTX_SAVE_PTR: *const TaskContext = core::ptr::null();

extern "C" fn ctx_bounce_entry() {
    crate::println!("[la-ctx] bounce entered, switching back");
    unsafe {
        switch_task_context(
            core::ptr::addr_of_mut!(CTX_BOUNCE_STACK) as *mut TaskContext,
            CTX_SAVE_PTR,
        );
    }
}

pub fn loongarch64_ctx_smoke() {
    crate::println!("[la-ctx] testing switch_task_context");
    let stack_top = unsafe { core::ptr::addr_of!(CTX_BOUNCE_STACK) as usize + 4096 };
    let bounce_ctx = TaskContext::new_kernel_context(ctx_bounce_entry as usize, stack_top);
    let mut save_ctx = TaskContext::zero_init();

    unsafe {
        CTX_SAVE_PTR = core::ptr::addr_of!(save_ctx);
        switch_task_context(
            core::ptr::addr_of_mut!(save_ctx),
            &bounce_ctx as *const TaskContext,
        );
    }

    crate::println!("[la-ctx] switch_task_context round-trip passed");
}

