const ENTRY_COUNT: usize = 512;
const PAGE_SIZE_BITS: usize = 12;

const PTE_V: usize = 1 << 0;
const PTE_D: usize = 1 << 1;
const PTE_PLV_L: usize = 1 << 2;
const PTE_PLV_H: usize = 1 << 3;
const PTE_MAT_L: usize = 1 << 4;
const PTE_P: usize = 1 << 7;
const PTE_W: usize = 1 << 8;
const PTE_NR: usize = 1 << 61;
const PTE_NX: usize = 1 << 62;

const PPN_MASK: usize = 0x1fff_ffff_ffff_f000;

const CSR_TLBIDX: usize = 0x10;
const CSR_ASID: usize = 0x18;
const CSR_PGDL: usize = 0x19;
const CSR_PWCL: usize = 0x1c;
const CSR_PWCH: usize = 0x1d;
const CSR_STLBPS: usize = 0x1e;
const CSR_TLBRENTRY: usize = 0x88;
const CSR_TLBREHI: usize = 0x8e;
const VIRT_OFFSET: usize = 0x9000_0000_0000_0000;

const PAGE_SIZE_FIELD: usize = 12;
const TLBIDX_PS_SHIFT: usize = 24;
const TLBIDX_PS_MASK: usize = 0x3f << TLBIDX_PS_SHIFT;
const PWCL_4K_4LEVEL: usize = 0x13e4_d52c;
const PWCH_4K_4LEVEL: usize = 0x267;

