#[derive(Copy, Clone)]
#[repr(transparent)]
pub struct LoongArchPte(pub usize);

impl LoongArchPte {
    pub const fn empty() -> Self {
        Self(0)
    }

    pub fn is_empty(&self) -> bool {
        self.0 == 0
    }

    pub fn is_valid(&self) -> bool {
        self.0 & PTE_V != 0
    }

    pub fn ppn(&self) -> PhysPageNum {
        PhysPageNum((self.0 & PPN_MASK) >> PAGE_SIZE_BITS)
    }

    pub fn new_table(ppn: PhysPageNum) -> Self {
        Self(ppn.0 << PAGE_SIZE_BITS)
    }

    pub fn new_page(ppn: PhysPageNum, flags: usize) -> Self {
        Self((ppn.0 << PAGE_SIZE_BITS) | flags)
    }
}

pub struct LoongArchPageTable {
    root_ppn: PhysPageNum,
    frames: Vec<PhysPageNum>,
}

impl LoongArchPageTable {
    fn pte_array(ppn: PhysPageNum) -> &'static mut [LoongArchPte; ENTRY_COUNT] {
        let pa: PhysAddr = ppn.into();
        let va = pa.0 | VIRT_OFFSET;
        unsafe { &mut *(va as *mut [LoongArchPte; ENTRY_COUNT]) }
    }

    fn vpn_indexes(vpn: VirtPageNum) -> [usize; 4] {
        let vpn = vpn.0;
        [
            (vpn >> 27) & 0x1ff,
            (vpn >> 18) & 0x1ff,
            (vpn >> 9) & 0x1ff,
            vpn & 0x1ff,
        ]
    }

    fn flags_from_perm(perm: MapPermission) -> usize {
        let mut flags = PTE_V | PTE_D | PTE_P | PTE_MAT_L;

        if perm.user {
            flags |= PTE_PLV_L | PTE_PLV_H;
        }
        if perm.write {
            flags |= PTE_W;
        }
        if !perm.read {
            flags |= PTE_NR;
        }
        if !perm.execute {
            flags |= PTE_NX;
        }

        flags
    }

    fn find_pte_create(&mut self, vpn: VirtPageNum) -> &'static mut LoongArchPte {
        let indexes = Self::vpn_indexes(vpn);
        let mut ppn = self.root_ppn;

        for &index in indexes.iter().take(3) {
            let pte_array = Self::pte_array(ppn);
            let pte = &mut pte_array[index];

            if pte.is_empty() {
                let new_ppn = frame_alloc().expect("failed to allocate LoongArch page table frame");
                zero_frame(new_ppn);
                self.frames.push(new_ppn);
                *pte = LoongArchPte::new_table(new_ppn);
            }

            ppn = pte.ppn();
        }

        let pte_array = Self::pte_array(ppn);
        &mut pte_array[indexes[3]]
    }

    fn find_pte(&self, vpn: VirtPageNum) -> Option<&'static mut LoongArchPte> {
        let indexes = Self::vpn_indexes(vpn);
        let mut ppn = self.root_ppn;

        for &index in indexes.iter().take(3) {
            let pte_array = Self::pte_array(ppn);
            let pte = &mut pte_array[index];

            if pte.is_empty() {
                return None;
            }

            ppn = pte.ppn();
        }

        let pte_array = Self::pte_array(ppn);
        Some(&mut pte_array[indexes[3]])
    }
}

impl PageTable for LoongArchPageTable {
    fn new() -> Self {
        let root_ppn = frame_alloc().expect("failed to allocate LoongArch root page table");
        zero_frame(root_ppn);

        let mut frames = Vec::new();
        frames.push(root_ppn);

        crate::kprintln!(
            "[loongarch64 mm] root page table frame allocated: ppn={:#x}, pa={:#x}",
            root_ppn.0,
            root_ppn.0 << PAGE_SIZE_BITS
        );

        Self { root_ppn, frames }
    }

    fn map(&mut self, vpn: VirtPageNum, ppn: PhysPageNum, perm: MapPermission) {
        let pte = self.find_pte_create(vpn);

        // Allow overwriting user pages (for MAP_FIXED, mprotect, COW)
        if !pte.is_empty() && perm.user {
            *pte = LoongArchPte::new_page(ppn, Self::flags_from_perm(perm));
            unsafe { core::arch::asm!("invtlb 0, $zero, $zero"); }
            return;
        }

        if !pte.is_empty() {
            panic!("[loongarch64 mm] vpn already mapped: {:#x}", vpn.0);
        }

        *pte = LoongArchPte::new_page(ppn, Self::flags_from_perm(perm));
    }

    fn unmap(&mut self, vpn: VirtPageNum) {
        let pte = self
            .find_pte(vpn)
            .expect("[loongarch64 mm] vpn is not mapped");

        if !pte.is_valid() {
            panic!("[loongarch64 mm] vpn is not mapped: {:#x}", vpn.0);
        }

        *pte = LoongArchPte::empty();
    }

    fn translate(&self, vpn: VirtPageNum) -> Option<PhysPageNum> {
        let pte = self.find_pte(vpn)?;

        if pte.is_valid() {
            Some(pte.ppn())
        } else {
            None
        }
    }

    fn token(&self) -> usize {
        self.root_ppn.0 << PAGE_SIZE_BITS
    }
}

impl Drop for LoongArchPageTable {
    fn drop(&mut self) {
        let count = self.frames.len();

        for ppn in self.frames.drain(..) {
            frame_dealloc(ppn);
        }

        if count > 0 {
            crate::kprintln!("[mm] drop LoongArch page table frames={}", count);
        }
    }
}

