const MEMORY_END: usize = 0x0800_0000;
#[cfg(not(feature = "arch_loongarch64"))]
const MEMORY_END: usize = 0x8800_0000;
const MAX_RECYCLED_FRAMES: usize = 65536;

pub struct StackFrameAllocator {
    current: usize,
    end: usize,
    recycled: [usize; MAX_RECYCLED_FRAMES],
    recycled_top: usize,
}

impl StackFrameAllocator {
    pub const fn new() -> Self {
        Self {
            current: 0,
            end: 0,
            recycled: [0; MAX_RECYCLED_FRAMES],
            recycled_top: 0,
        }
    }

    pub fn init(&mut self, start_ppn: PhysPageNum, end_ppn: PhysPageNum) {
        self.current = start_ppn.0;
        self.end = end_ppn.0;
        self.recycled_top = 0;
    }

    pub fn alloc(&mut self) -> Option<PhysPageNum> {
        if self.recycled_top > 0 {
            self.recycled_top -= 1;
            Some(PhysPageNum(self.recycled[self.recycled_top]))
        } else if self.current < self.end {
            let ppn = self.current;
            self.current += 1;
            Some(PhysPageNum(ppn))
        } else {
            None
        }
    }

    pub fn dealloc(&mut self, ppn: PhysPageNum) {
        if self.recycled_top >= MAX_RECYCLED_FRAMES {
            // Drop excess frames when recycled stack is full
            return;
        }

        // Defend against double-free: scan the recycled stack for this PPN.
        // A double-free means the same frame was in two MapArea data_frames
        // lists, which indicates a bug elsewhere. Skip the duplicate.
        for i in 0..self.recycled_top {
            if self.recycled[i] == ppn.0 {
                crate::kprintln!("[frame] double-free detected: ppn={:#x}", ppn.0);
                return;
            }
        }

        self.recycled[self.recycled_top] = ppn.0;
        self.recycled_top += 1;
    }
}

static mut FRAME_ALLOCATOR: StackFrameAllocator = StackFrameAllocator::new();

// COW reference counts for physical frames.
// Indexed by physical page number. Tracks how many page table entries
// share this frame (for copy-on-write detection).
const MAX_FRAMES: usize = 65536;
static mut FRAME_REFCOUNT: [u16; MAX_FRAMES] = [0u16; MAX_FRAMES];

pub fn frame_refcount_inc(ppn: PhysPageNum) {
    let idx = ppn.0;
    if idx < MAX_FRAMES {
        unsafe { FRAME_REFCOUNT[idx] = FRAME_REFCOUNT[idx].saturating_add(1); }
    }
}

pub fn frame_refcount_dec(ppn: PhysPageNum) -> bool {
    let idx = ppn.0;
    if idx < MAX_FRAMES {
        unsafe {
            if FRAME_REFCOUNT[idx] > 0 {
                FRAME_REFCOUNT[idx] -= 1;
            }
            FRAME_REFCOUNT[idx] > 0
        }
    } else {
        false
    }
}

pub fn frame_is_shared(ppn: PhysPageNum) -> bool {
    let idx = ppn.0;
    if idx < MAX_FRAMES {
        unsafe { FRAME_REFCOUNT[idx] > 1 }
    } else {
        false
    }
}

