pub fn init_frame_allocator() {
    #[cfg(feature = "arch_loongarch64")]
    let kernel_end = ekernel as usize & !0x9000_0000_0000_0000;
    #[cfg(not(feature = "arch_loongarch64"))]
    let kernel_end = ekernel as usize;
    let start = PhysAddr(kernel_end).ceil();
    let end = PhysAddr(MEMORY_END).floor();

    crate::kprintln!(
        "[mm] frame allocator: kernel_end={:#x}, start_ppn={:#x}, end_ppn={:#x}",
        kernel_end,
        start.0,
        end.0
    );

    unsafe {
        FRAME_ALLOCATOR.init(start, end);
    }
}
pub fn frame_alloc() -> Option<PhysPageNum> {
    unsafe { FRAME_ALLOCATOR.alloc() }
}

pub fn frame_dealloc(ppn: PhysPageNum) {
    unsafe {
        FRAME_ALLOCATOR.dealloc(ppn);
    }
}

pub fn zero_frame(ppn: PhysPageNum) {
    let pa: PhysAddr = ppn.into();
    let ptr = phys_to_kvirt(pa.0) as *mut u64;
    for i in 0..(PAGE_SIZE / 8) {
        unsafe {
            ptr.add(i).write_volatile(0);
        }
    }
}

pub fn memory_end() -> usize {
    MEMORY_END
}

