pub struct Locked<T> {
    inner: UnsafeCell<T>,
}

// 当前阶段为单核 -smp 1；后续多核时这里要换成真正的锁/关中断锁。
unsafe impl<T> Sync for Locked<T> {}

impl<T> Locked<T> {
    pub const fn new(inner: T) -> Self {
        Self {
            inner: UnsafeCell::new(inner),
        }
    }

    pub fn lock(&self) -> &mut T {
        unsafe { &mut *self.inner.get() }
    }
}

#[repr(C)]
struct FreeBlock {
    size: usize,
    next: *mut FreeBlock,
}

#[repr(C)]
struct AllocHeader {
    start: usize,
    size: usize,
}

pub struct HeapAllocator {
    head: FreeBlock,
    initialized: bool,
}

impl HeapAllocator {
    pub const fn new() -> Self {
        Self {
            head: FreeBlock {
                size: 0,
                next: null_mut(),
            },
            initialized: false,
        }
    }

    pub unsafe fn init(&mut self, heap_start: usize, heap_size: usize) {
        let start = align_up(heap_start, align_of::<FreeBlock>());
        let end = align_down(heap_start + heap_size, align_of::<FreeBlock>());

        if end <= start || end - start < min_block_size() {
            panic!("[heap] invalid heap region");
        }

        self.head.next = null_mut();
        self.initialized = true;

        unsafe {
            self.add_free_region(start, end - start);
        }
    }

    unsafe fn add_free_region(&mut self, start: usize, size: usize) {
        let heap_start = kernel_heap_start();
        let heap_end = kernel_heap_end();

        let raw_start = start;
        let raw_end = match raw_start.checked_add(size) {
            Some(end) => end,
            None => {
                panic!(
                    "[heap] add_free_region overflow: start={:#x}, size={:#x}",
                    raw_start, size
                );
            }
        };

        if raw_start < heap_start || raw_start >= heap_end || raw_end > heap_end {
            panic!(
                "[heap] add_free_region out of heap: region={:#x}..{:#x}, heap={:#x}..{:#x}",
                raw_start, raw_end, heap_start, heap_end
            );
        }

        let start = align_up(raw_start, align_of::<FreeBlock>());
        let end = align_down(raw_end, align_of::<FreeBlock>());

        if end <= start {
            return;
        }

        let size = end - start;

        if size < min_block_size() {
            return;
        }

        let mut prev: *mut FreeBlock = &mut self.head;
        let mut curr = (*prev).next;

        while !curr.is_null() && (curr as usize) < start {
            prev = curr;
            curr = (*curr).next;
        }

        /*
         * 插入前检查和前一个块是否重叠。
         * 注意：必须在 new_block.write() 之前检查，否则 double free 会先污染链表。
         */
        if prev != (&mut self.head as *mut FreeBlock) {
            let prev_start = prev as usize;
            let prev_end = prev_start + (*prev).size;

            if prev_end > start {
                panic!(
                    "[heap] add_free_region overlap previous: prev={:#x}..{:#x}, new={:#x}..{:#x}",
                    prev_start, prev_end, start, end
                );
            }
        }

        /*
         * 插入前检查和后一个块是否重叠。
         */
        if !curr.is_null() {
            let curr_start = curr as usize;

            if end > curr_start {
                panic!(
                    "[heap] add_free_region overlap next: new={:#x}..{:#x}, next_start={:#x}",
                    start, end, curr_start
                );
            }
        }

        let new_block = start as *mut FreeBlock;

        new_block.write(FreeBlock { size, next: curr });

        (*prev).next = new_block;

        self.coalesce_with_next(new_block);

        if prev != (&mut self.head as *mut FreeBlock) {
            self.coalesce_with_next(prev);
        }
    }

    unsafe fn coalesce_with_next(&mut self, block: *mut FreeBlock) {
        if block.is_null() {
            return;
        }

        let next = unsafe { (*block).next };
        if next.is_null() {
            return;
        }

        let block_start = block as usize;
        let block_end = block_start + unsafe { (*block).size };
        let next_start = next as usize;

        if block_end == next_start {
            unsafe {
                (*block).size += (*next).size;
                (*block).next = (*next).next;
            }
        }
    }

    fn alloc_from_region(
        &self,
        block_start: usize,
        block_size: usize,
        layout: Layout,
    ) -> Option<(usize, usize, usize)> {
        let block_end = block_start.checked_add(block_size)?;

        let alloc_size = max(layout.size(), 1);
        let align = max(layout.align(), align_of::<AllocHeader>());

        let mut user_start = align_up(block_start + size_of::<AllocHeader>(), align);
        let mut header_start = user_start.checked_sub(size_of::<AllocHeader>())?;
        let mut alloc_start = header_start;

        let prefix = alloc_start.checked_sub(block_start)?;
        if prefix > 0 && prefix < min_block_size() {
            user_start = align_up(
                block_start + min_block_size() + size_of::<AllocHeader>(),
                align,
            );
            header_start = user_start.checked_sub(size_of::<AllocHeader>())?;
            alloc_start = header_start;
        }

        let mut alloc_end = align_up(user_start.checked_add(alloc_size)?, align_of::<FreeBlock>());

        if alloc_end > block_end {
            return None;
        }

        let suffix = block_end - alloc_end;
        if suffix > 0 && suffix < min_block_size() {
            alloc_end = block_end;
        }

        if alloc_start < block_start || alloc_end > block_end {
            return None;
        }

        Some((alloc_start, user_start, alloc_end))
    }

    pub unsafe fn alloc(&mut self, layout: Layout) -> *mut u8 {
        if !self.initialized {
            crate::kprintln!(
                "[heap] alloc before init: size={}, align={}",
                layout.size(),
                layout.align(),
            );
            return null_mut();
        }

        if layout.size() > 0x10_0000 {
            crate::kprintln!(
                "[heap] LARGE ALLOC: size={}, align={}",
                layout.size(),
