use crate::mm::page_table::{MapPermission, PageTable};
use alloc::vec::Vec;

#[cfg(feature = "arch_loongarch64")]
pub(crate) fn phys_to_kvirt(pa: usize) -> usize {
    pa | 0x9000_0000_0000_0000
}

#[cfg(not(feature = "arch_loongarch64"))]
pub(crate) fn phys_to_kvirt(pa: usize) -> usize {
    pa
}

const UART0: usize = 0x1000_0000;
const UART0_SIZE: usize = 0x1000;
const VIRTIO_MMIO_BASE: usize = 0x1000_1000;
const VIRTIO_MMIO_SIZE: usize = 0x1000;
const VIRTIO_MMIO_COUNT: usize = 8;

// Memory layout is arch-specific because ELF load addresses differ.
// RISC-V: Sv39 virtual address space, ELFs linked near 0x10000.
// LoongArch: 48-bit VA space, ELFs may link at 0x1_2000_0000+.

#[cfg(feature = "arch_riscv64")]
pub const USER_STACK_TOP: usize = 0x0000_0000_8000_0000;
#[cfg(feature = "arch_riscv64")]
const USER_MMAP_BASE: usize = 0x0000_0000_4000_0000;

#[cfg(feature = "arch_loongarch64")]
pub const USER_STACK_TOP: usize = 0x0000_7FFF_FFFF_F000; // top of 48-bit user space - 1 page
#[cfg(feature = "arch_loongarch64")]
const USER_MMAP_BASE: usize = 0x0000_0001_0000_0000; // start mmap at 4GB to stay clear of ELF segments

pub const USER_STACK_SIZE: usize = 0x80_0000; // 8MB VA reservation
pub const USER_STACK_ALLOC: usize = 0x8_0000; // 512KB physical at top
pub const USER_STACK_BOTTOM: usize = USER_STACK_TOP - USER_STACK_SIZE;
pub struct MemorySet {
    page_table: ArchPageTable,
    areas: Vec<MapArea>,
    heap_start: usize,
    program_brk: usize,
    pub mmap_top: usize,
    pub stack_alloc: usize,  // per-process stack physical allocation
}

#[derive(Copy, Clone)]
pub enum MapType {
    Identical,
    Framed,
}

#[derive(Copy, Clone, Debug)]
pub enum MapAreaType {
    KernelText,
    KernelRodata,
    KernelData,
    KernelBss,
    KernelHeap,
    KernelFree,
    Mmio,
    ElfLoad,
    UserStack,
    UserHeap,
    Mmap,
}

// #[derive(Clone)]
pub struct MapArea {
    vpn_range: VPNRange,
    map_type: MapType,
    perm: MapPermission,
    area_type: MapAreaType,
    data_frames: Vec<(VirtPageNum, PhysPageNum)>,
}

impl MapArea {
    pub fn new(
        start_va: VirtAddr,
        end_va: VirtAddr,
        map_type: MapType,
        perm: MapPermission,
        area_type: MapAreaType,
    ) -> Self {
        Self {
            vpn_range: VPNRange::new(start_va.floor(), end_va.ceil()),
            map_type,
            perm,
            area_type,
            data_frames: Vec::new(),
        }
    }

    pub fn is_user_heap(&self) -> bool {
        matches!(self.area_type, MapAreaType::UserHeap)
    }

    // 把该区域的结束地址扩展到新的地址，并为新增页建立映射
    pub fn append_to<T: PageTable>(&mut self, page_table: &mut T, new_end_va: VirtAddr) {
        let old_end_vpn = self.vpn_range.end();
        let new_end_vpn = new_end_va.ceil();

        if new_end_vpn <= old_end_vpn {
            return;
        }

        for vpn in VPNRange::new(old_end_vpn, new_end_vpn) {
            self.map_one(page_table, vpn);
        }

        self.vpn_range = VPNRange::new(self.vpn_range.start(), new_end_vpn);
    }

    // 调试输出
    pub fn data_frame_count(&self) -> usize {
        self.data_frames.len()
    }

    fn map_one<T: PageTable>(&mut self, page_table: &mut T, vpn: VirtPageNum) {
        let ppn = match self.map_type {
            MapType::Identical => PhysPageNum(vpn.0),
            MapType::Framed => {
                let ppn = frame_alloc().expect("failed to allocate frame for framed mapping");
                zero_frame(ppn);
                self.data_frames.push((vpn, ppn));
                ppn
            }
        };

        page_table.map(vpn, ppn, self.perm);
    }

    pub fn map<T: PageTable>(&mut self, page_table: &mut T) {
        for vpn in self.vpn_range {
            self.map_one(page_table, vpn);
        }
    }

    fn clone_metadata(&self) -> Self {
        Self {
            vpn_range: self.vpn_range,
            map_type: self.map_type,
            perm: self.perm,
            area_type: self.area_type,
            data_frames: Vec::new(),
        }
    }

    fn copy_data_to<T: PageTable>(&self, src_page_table: &T, dst_area: &Self, dst_page_table: &T) {
        match self.map_type {
            MapType::Framed => {}

            MapType::Identical => {
                panic!(
                    "[mm] fork user space: user area must not be identical mapped: area={:?}",
                    self.area_type,
                );
            }
        }

        for vpn in self.vpn_range {
            let src_ppn = src_page_table
                .translate(vpn)
                .expect("[mm] fork user space: source vpn not mapped");

            let dst_ppn = dst_page_table
                .translate(vpn)
                .expect("[mm] fork user space: destination vpn not mapped");

            copy_physical_page(src_ppn, dst_ppn);
        }

        if self.data_frames.len() != dst_area.data_frames.len() {
            panic!(
                "[mm] fork user space: frame count mismatch: area={:?}, src={}, dst={}",
                self.area_type,
                self.data_frames.len(),
                dst_area.data_frames.len(),
            );
        }
    }

    pub fn contains_va(&self, va: VirtAddr) -> bool {
        self.vpn_range.contains(va.floor())
    }

    pub fn area_type(&self) -> MapAreaType {
        self.area_type
    }

    pub fn perm(&self) -> MapPermission {
        self.perm
    }

    pub fn start_vpn(&self) -> VirtPageNum {
        self.vpn_range.start()
    }

    pub fn end_vpn(&self) -> VirtPageNum {
        self.vpn_range.end()
    }
}

fn copy_physical_page(src_ppn: PhysPageNum, dst_ppn: PhysPageNum) {
    let src_pa: PhysAddr = src_ppn.into();
    let dst_pa: PhysAddr = dst_ppn.into();

    let src = phys_to_kvirt(src_pa.0) as *const u64;
    let dst = phys_to_kvirt(dst_pa.0) as *mut u64;

    for i in 0..(PAGE_SIZE / 8) {
        unsafe {
            dst.add(i).write_volatile(src.add(i).read_volatile());
        }
    }
}

impl Drop for MapArea {
    fn drop(&mut self) {
        let count = self.data_frames.len();

        for (_vpn, ppn) in self.data_frames.drain(..) {
            frame_dealloc(ppn);
        }

        if count > 0 {
            crate::kprintln!("[mm] drop map area: {:?}, frames={}", self.area_type, count);
        }
    }
}

