            VirtAddr(etext as usize),
            MapType::Identical,
            MapPermission::kernel_rx(),
            MapAreaType::KernelText,
        ));

        self.push_area(MapArea::new(
            VirtAddr(srodata as usize),
            VirtAddr(erodata as usize),
            MapType::Identical,
            MapPermission::kernel_r(),
            MapAreaType::KernelRodata,
        ));

        self.push_area(MapArea::new(
            VirtAddr(sdata as usize),
            VirtAddr(edata as usize),
            MapType::Identical,
            MapPermission::kernel_rw(),
            MapAreaType::KernelData,
        ));

        self.push_area(MapArea::new(
            VirtAddr(sbss as usize),
            VirtAddr(ebss as usize),
            MapType::Identical,
            MapPermission::kernel_rw(),
            MapAreaType::KernelBss,
        ));

        self.push_area(MapArea::new(
