            VirtAddr(ekernel as usize),
            VirtAddr(memory_end()),
            MapType::Identical,
            MapPermission::kernel_rw(),
            MapAreaType::KernelFree,
        ));

        self.push_area(MapArea::new(
            VirtAddr(UART0),
            VirtAddr(UART0 + UART0_SIZE),
            MapType::Identical,
            MapPermission::kernel_rw(),
            MapAreaType::Mmio,
        ));

        self.push_area(MapArea::new(
            VirtAddr(VIRTIO_MMIO_BASE),
            VirtAddr(VIRTIO_MMIO_BASE + VIRTIO_MMIO_SIZE * VIRTIO_MMIO_COUNT),
            MapType::Identical,
            MapPermission::kernel_rw(),
            MapAreaType::Mmio,
        ));
    }

    pub fn new_kernel() -> Self {
        let mut memory_set = Self::new_bare();
        #[cfg(not(feature = "arch_loongarch64"))]
        memory_set.map_kernel_sections();
        memory_set
    }
}

impl Drop for MemorySet {
    fn drop(&mut self) {
        let token = self.token();
        let area_count = self.areas.len();

        crate::kprintln!(
            "[mm] drop memory set: token={:#x}, areas={}",
            token,
            area_count
        );

        self.areas.clear();
    }
}

