#[repr(C)]
#[derive(Copy, Clone)]
pub struct TrapContext {
    pub x: [usize; 32],

    #[cfg(feature = "arch_riscv64")]
    pub sstatus: usize,

    #[cfg(feature = "arch_riscv64")]
    pub sepc: usize,

    #[cfg(feature = "arch_riscv64")]
    pub scause: usize,

    #[cfg(feature = "arch_riscv64")]
    pub stval: usize,

    #[cfg(feature = "arch_loongarch64")]
    pub prmd: usize,   // same offset as sstatus (256)

    #[cfg(feature = "arch_loongarch64")]
    pub era: usize,    // same offset as sepc (264)

    #[cfg(feature = "arch_loongarch64")]
    pub estat: usize,  // same offset as scause (272)

    #[cfg(feature = "arch_loongarch64")]
    pub badv: usize,   // same offset as stval (280)
}

impl TrapContext {
    #[cfg(feature = "arch_riscv64")]
    pub fn from_user(&self) -> bool {
        self.sstatus & (1 << 8) == 0
    }

    #[cfg(feature = "arch_loongarch64")]
    pub fn from_user(&self) -> bool {
        self.prmd & 0x3 == 3
    }

    #[cfg(feature = "arch_riscv64")]
    pub fn from_supervisor(&self) -> bool {
        self.sstatus & (1 << 8) != 0
    }

    #[cfg(feature = "arch_loongarch64")]
    pub fn from_supervisor(&self) -> bool {
        self.prmd & 0x3 != 3
    }

    #[cfg(feature = "arch_riscv64")]
    pub fn cause_code(&self) -> usize {
        self.scause & 0xfff
    }

    #[cfg(feature = "arch_loongarch64")]
    pub fn cause_code(&self) -> usize {
        (self.estat >> 16) & 0x3f
    }

    #[cfg(feature = "arch_riscv64")]
    pub fn is_interrupt(&self) -> bool {
        (self.scause >> (usize::BITS as usize - 1)) != 0
    }

    #[cfg(feature = "arch_loongarch64")]
    pub fn is_interrupt(&self) -> bool {
        false
    }

    #[cfg(feature = "arch_riscv64")]
    pub fn app_init_context(entry: usize, user_sp: usize, tls: usize) -> Self {
        let mut cx = Self {
            x: [0; 32],
            sstatus: 0,
            sepc: entry,
            scause: 0,
            stval: 0,
        };
        cx.x[1] = entry;  // ra = entry (sentinel against accidental ret to 0)
        cx.x[2] = user_sp;
        cx.x[4] = tls;   // tp register for RISC-V TLS
        cx.sstatus &= !(1 << 8);
        cx.sstatus |= 1 << 5;
        // Enable user floating-point instructions for glibc lp64d binaries.
        // LemonCore does not yet implement lazy FPU context switching, but
        // Basic runs mostly serially; allowing FS=Dirty is enough to avoid
        // illegal-instruction traps in static glibc BusyBox and test loaders.
        cx.sstatus |= 3 << 13;
        cx
    }

    #[cfg(feature = "arch_loongarch64")]
    pub fn app_init_context(entry: usize, user_sp: usize, tls: usize) -> Self {
        let mut cx = Self {
            x: [0; 32],
            prmd: 0x7,
            era: entry,
            estat: 0,
            badv: 0,
        };
        cx.x[1] = entry;   // ra = entry (sentinel against accidental ret to 0)
        cx.x[3] = user_sp;  // sp (stack pointer)
        cx.x[2] = tls;      // tp (TLS thread pointer)
