fn fork_current_user_process_with_child_stack(child_stack: Option<usize>) -> isize {
    let child_pid = alloc_pid();

    let (parent_pid, child_memory_set, child_trap_cx, child_cwd, child_files) = {
        let parent = current();

        if parent.kind() != TaskKind::UserProcess {
            panic!(
                "[fork] fork from non-user task: pid={}, kind={:?}",
                parent.pid(),
                parent.kind(),
            );
        }

        crate::kprintln!("[fork] begin: parent={}, child={}", parent.pid(), child_pid,);

        let child_memory_set = parent.memory_set().fork_user_space();
        let child_trap_cx = parent.fork_child_trap_context(child_stack);
        let child_cwd = String::from(parent.cwd());
        let child_files = parent.cloned_user_files();

        (
            parent.pid(),
            child_memory_set,
            child_trap_cx,
            child_cwd,
            child_files,
        )
    };

    let child = TaskControlBlock::new_forked_user_process(
        child_pid,
        parent_pid,
        child_memory_set,
        child_trap_cx,
        child_cwd,
        child_files,
    );

    {
        let parent = current();
        parent.add_child(child_pid);

        crate::kprintln!(
            "[fork] relation: parent={}, children={:?}, child_parent={}",
            parent.pid(),
            parent.children(),
            parent_pid,
        );
    }

    manager::add(child);

    crate::kprintln!(
        "[fork] done: parent={}, child={}, ready_count={}",
        parent_pid,
        child_pid,
        manager::ready_count(),
    );

    child_pid as isize
}

