pub fn send_signal_to_pid(pid: usize, signo: usize) -> isize {
    if signo > 63 {
        return -1;
    }
    // Signal 0: permission check — always succeed
    if signo == 0 {
        return 0;
    }

    let sig_mask: u64 = 1u64 << (signo as u64);
    let cur_pid = current().pid();

    // Send to self or kill(-1)
    if pid == 0 || pid == cur_pid {
        current().pending_signals |= sig_mask;
        crate::kprintln!("[signal] sent signal {} to current pid={}", signo, cur_pid);
        return 0;
    }

    // Look up target in ready queue
    if let Some(task) = crate::task::manager::find_in_ready(pid) {
        task.pending_signals |= sig_mask;
        // Wake up if blocked
        if task.status() == TaskStatus::Blocked {
            task.set_status(TaskStatus::Ready);
        }
        crate::kprintln!("[signal] sent signal {} to pid={}", signo, pid);
    } else {
        crate::kprintln!("[signal] pid={} not found in ready queue, signal {} ignored", pid, signo);
    }
    0
}

