            pid,
            parent,
            entry,
            user_stack_top,
            memory_set.token(),
            kernel_stack_id,
            kernel_stack::kernel_stack_top(kernel_stack_id),
            trap_cx_ptr as usize,
        );

        Self {
            pid,
            status: TaskStatus::Ready,
            kind: TaskKind::UserProcess,
            memory_set: Some(memory_set),
            kernel_stack_id,
