        self.current = Some(task);
    }

    pub fn current(&mut self) -> &mut TaskControlBlock {
        self.current.as_mut().expect("[task] no current task")
    }

    pub fn scheduler_cx_ptr(&mut self) -> *mut crate::arch::TaskContext {
        &mut self.scheduler_cx as *mut _
    }

    pub fn current_task_cx_ptr(&mut self) -> *mut crate::arch::TaskContext {
        self.current().task_cx_ptr()
    }
}

static mut PROCESSOR: Processor = Processor::new();

pub fn init(task: TaskControlBlock) {
    unsafe {
        PROCESSOR.set_current(task);
    }
}

pub fn current() -> &'static mut TaskControlBlock {
    unsafe { PROCESSOR.current() }
}

pub fn take_current() -> TaskControlBlock {
    unsafe { PROCESSOR.take_current() }
}

pub fn set_current(task: TaskControlBlock) {
    unsafe {
        PROCESSOR.set_current(task);
    }
}

pub fn scheduler_cx_ptr() -> *mut crate::arch::TaskContext {
    unsafe { PROCESSOR.scheduler_cx_ptr() }
}

pub fn current_task_cx_ptr() -> *mut crate::arch::TaskContext {
    unsafe { PROCESSOR.current_task_cx_ptr() }
}

pub fn run() -> ! {
    run_current()
}

pub fn run_task(task: TaskControlBlock) -> ! {
    set_current(task);
    run_current()
}

pub fn run_current() -> ! {
    match current().kind() {
        TaskKind::UserProcess => {
            run_user_current();
        }

        TaskKind::KernelThread => {
            /*
             * run_current() 仍然是“不会返回”的入口。
             * KernelThread 的 TaskContext 调度会返回 scheduler，
             * 所以不应该从这个旧入口直接运行。
             */
            crate::println!(
                "[task] ERROR: run_current got KernelThread: pid={}, kstack_top={:#x}",
                current().pid(),
                current().kernel_stack_top(),
            );

            panic!("[task] KernelThread should be dispatched by scheduler");
        }
    }
}

pub fn run_user_current() -> ! {
    let task = current();

    if task.kind() != TaskKind::UserProcess {
        panic!("[task] run_user_current got non-user task");
    }

    let pid = task.pid();
    let token = task.token();
    let kstack_top = task.kernel_stack_top();
    let trap_cx_ptr = task.trap_cx_ptr();

    task.set_status(TaskStatus::Running);

    // crate::mm::heap_allocator::dump_heap_allocator_state("run_user_current before user activate");

    task.memory_set().activate();

    // crate::mm::heap_allocator::dump_heap_allocator_state("run_user_current after user activate");

    unsafe {
        write_trap_stack_top(kstack_top);
    }

    crate::arch::enable_timer_interrupt();
    crate::arch::set_next_timer();

    // A blocked user task leaves its trap frame on the kernel stack while the
    // scheduler runs on a different path. Restore the saved frame
    // unconditionally on wake; checking only sepc/era misses partial register
    // corruption.
    let cx = unsafe { &mut *trap_cx_ptr };
    #[cfg(feature = "arch_riscv64")]
    let is_corrupt = cx.sepc >= crate::mm::memory_set::USER_STACK_BOTTOM && cx.sepc != 0;
    #[cfg(feature = "arch_loongarch64")]
    let is_corrupt = cx.era >= crate::mm::memory_set::USER_STACK_BOTTOM && cx.era != 0;

    if let Some(backup) = task.saved_trap_cx.take() {
        unsafe { core::ptr::write(trap_cx_ptr, backup); }
    } else if is_corrupt {
        crate::println!("[task] CORRUPT TRAP CTX pid={} no backup - panic", pid);
        panic!("corrupt trap context");
    }

    unsafe {
        __restore_user(trap_cx_ptr as *const TrapContext);
    }
}

pub fn run_kernel_current() {
    let task = current();

    if task.kind() != TaskKind::KernelThread {
        panic!("[task] run_kernel_current got non-kernel thread");
    }

    let pid = task.pid();
    let kstack_top = task.kernel_stack_top();

    crate::kprintln!(
        "[task] switch to kernel thread: pid={}, kstack_top={:#x}",
        pid,
        kstack_top,
    );

    task.set_status(TaskStatus::Running);

    /*
     * KernelThread 不应该运行在某个用户进程的页表下。
     * 进入内核线程前先切回 kernel page table。
     */
    crate::mm::activate_kernel_space();

    let scheduler_cx = scheduler_cx_ptr();
    let task_cx = current_task_cx_ptr();

    crate::arch::switch_task_context(scheduler_cx, task_cx as *const _);

    /*
     * KernelThread 调用 kernel_yield/kernel_exit 后，
     * 会通过 switch_task_context 切回这里。
     */
    crate::kprintln!(
        "[task] back to scheduler from kernel thread: pid={}, status={:?}",
        current().pid(),
        current().status(),
    );
}

