pub fn alloc_kernel_stack() -> usize {
    unsafe {
        // crate::println!(
        //     "[task] alloc_kernel_stack: next={}, free_top={}",
        //     NEXT_KERNEL_STACK_ID,
        //     FREE_KERNEL_STACK_TOP
        // );

        if FREE_KERNEL_STACK_TOP > 0 {
            FREE_KERNEL_STACK_TOP -= 1;
            let id = FREE_KERNEL_STACKS[FREE_KERNEL_STACK_TOP];

            if id >= MAX_TASKS {
                panic!("[task] invalid reused kernel stack id: {}", id);
            }

            if KERNEL_STACK_USED[id] {
                panic!("[task] reused kernel stack still marked used: id={}", id);
            }

            KERNEL_STACK_USED[id] = true;

            crate::kprintln!(
                "[task] reuse kernel stack: id={}, bottom={:#x}, top={:#x}",
                id,
                kernel_stack_bottom(id),
                kernel_stack_top(id)
            );

            return id;
        }

        if NEXT_KERNEL_STACK_ID >= MAX_TASKS {
            panic!(
                "[task] kernel stack exhausted: next={}, max={}",
                NEXT_KERNEL_STACK_ID, MAX_TASKS
            );
        }

        let id = NEXT_KERNEL_STACK_ID;
        NEXT_KERNEL_STACK_ID += 1;

        if KERNEL_STACK_USED[id] {
            panic!("[task] new kernel stack already used: id={}", id);
        }

        KERNEL_STACK_USED[id] = true;

        crate::kprintln!(
            "[task] alloc kernel stack: id={}, bottom={:#x}, top={:#x}",
            id,
            kernel_stack_bottom(id),
            kernel_stack_top(id)
        );

        id
    }
}

pub fn dealloc_kernel_stack(id: usize) {
    unsafe {
        if id >= MAX_TASKS {
            panic!("[task] invalid kernel stack id: {}", id);
        }

        if !KERNEL_STACK_USED[id] {
            panic!("[task] double free kernel stack: id={}", id);
        }

        if FREE_KERNEL_STACK_TOP >= MAX_TASKS {
            panic!("[task] kernel stack free stack overflow");
        }

        KERNEL_STACK_USED[id] = false;
        FREE_KERNEL_STACKS[FREE_KERNEL_STACK_TOP] = id;
        FREE_KERNEL_STACK_TOP += 1;

        crate::kprintln!(
            "[task] dealloc kernel stack: id={}, bottom={:#x}, top={:#x}",
            id,
            kernel_stack_bottom(id),
            kernel_stack_top(id)
        );
    }
}

