fn read_superblock() -> Result<Ext4SuperBlockInfo, isize> {
    let mut buf = [0u8; EXT4_SUPERBLOCK_SIZE];

    let ret = crate::drivers::block_read_bytes(EXT4_SUPERBLOCK_OFFSET, &mut buf);

    if ret != EXT4_SUPERBLOCK_SIZE as isize {
        crate::println!("[ext4] read superblock failed: ret={}", ret);
        return Err(err(EIO));
    }

    let magic = read_u16(&buf, EXT4_MAGIC_OFFSET);
    if magic != EXT4_MAGIC {
        crate::kprintln!("[ext4] invalid magic: {:#x}", magic);
        return Err(err(EINVAL));
    }

    let inodes_count = read_u32(&buf, 0x00);
    let blocks_count = read_u32(&buf, 0x04);
    let first_data_block = read_u32(&buf, 0x14);
    let log_block_size = read_u32(&buf, 0x18);
    let blocks_per_group = read_u32(&buf, 0x20);
    let inodes_per_group = read_u32(&buf, 0x28);

    let inode_size = read_u16(&buf, 0x58);

    let block_size = 1024usize.checked_shl(log_block_size).ok_or(err(EINVAL))?;

    if block_size != 1024 && block_size != 2048 && block_size != 4096 {
        crate::println!(
            "[ext4] unsupported block size: log={}, size={}",
            log_block_size,
            block_size,
        );
        return Err(err(EINVAL));
    }

    if inode_size == 0 {
        crate::println!("[ext4] invalid inode size: 0");
        return Err(err(EINVAL));
    }

    Ok(Ext4SuperBlockInfo {
        inodes_count,
        blocks_count,
        first_data_block,
        log_block_size,
        block_size,
        blocks_per_group,
        inodes_per_group,
        inode_size,
    })
}

