fn read_inode(info: Ext4SuperBlockInfo, ino: u32) -> Result<Ext4InodeInfo, isize> {
    if ino == 0 {
        return Err(err(EINVAL));
    }

    let group_id = (ino - 1) / info.inodes_per_group;
    let index_in_group = (ino - 1) % info.inodes_per_group;

    let group = read_group_desc(info, group_id)?;

    let inode_offset = group.inode_table_block as usize * info.block_size
        + index_in_group as usize * info.inode_size as usize;

    let mut buf = [0u8; 256];

    if info.inode_size as usize > buf.len() {
        crate::println!(
            "[ext4] unsupported inode size: inode_size={}, max={}",
            info.inode_size,
            buf.len(),
        );
        return Err(err(EINVAL));
    }

    let ret =
        crate::drivers::block_read_bytes(inode_offset, &mut buf[..info.inode_size as usize]);

    if ret != info.inode_size as isize {
        crate::println!(
            "[ext4] read inode failed: ino={}, offset={:#x}, ret={}",
            ino,
            inode_offset,
            ret,
        );
        return Err(err(EIO));
    }

    let mode = read_u16(&buf, 0x00);
    let size = read_u32(&buf, 0x04);
    let blocks = read_u32(&buf, 0x1c);

    let mut block = [0u8; 60];
    block.copy_from_slice(&buf[0x28..0x28 + 60]);

    Ok(Ext4InodeInfo {
        ino,
        mode,
        size,
        blocks,
        block,
