fn parse_extent_header(block: &[u8; 60]) -> Result<Ext4ExtentHeader, isize> {
    let magic = read_u16(block, 0x00);
    if magic != EXT4_EXTENT_MAGIC {
        crate::println!(
            "[ext4] unsupported i_block format: extent magic={:#x}",
            magic,
        );
        return Err(err(EINVAL));
    }

    Ok(Ext4ExtentHeader {
        magic,
        entries: read_u16(block, 0x02),
        max: read_u16(block, 0x04),
        depth: read_u16(block, 0x06),
        generation: read_u32(block, 0x08),
    })
}

fn parse_extent(block: &[u8; 60], index: usize) -> Result<Ext4Extent, isize> {
    let offset = 12 + index * 12;

    if offset + 12 > block.len() {
        return Err(err(EINVAL));
    }

    Ok(Ext4Extent {
        logical_block: read_u32(block, offset + 0x00),
        len: read_u16(block, offset + 0x04),
        start_hi: read_u16(block, offset + 0x06),
        start_lo: read_u32(block, offset + 0x08),
    })
}

