pub fn lookup_path(path: &str) -> Result<Ext4InodeInfo, isize> {
    let info = info().ok_or(err(EINVAL))?;

    let mut current = read_inode(info, EXT4_ROOT_INO)?;

    if path.is_empty() || path == "/" {
        return Ok(current);
    }

    for component in path.split('/') {
        if component.is_empty() || component == "." {
            continue;
        }

        if component == ".." {
            crate::kprintln!("[ext4] parent path component unsupported: {}", path);
            return Err(err(ENOENT));
        }

        if !current.is_dir() {
            crate::kprintln!(
                "[ext4] path component parent is not dir: path={}, component={}, ino={}, mode={:#x}",
                path,
                component,
                current.ino,
                current.mode,
            );
            return Err(err(ENOTDIR));
        }

        let entry = lookup_in_dir(info, current, component)?;
        current = read_inode(info, entry.ino)?;
    }

    Ok(current)
}

