/// VFS page cache: maps (path, file_offset) → physical frame.
/// Chronix-equivalent: inode page cache. Pre-populated with builtin data.
static mut PAGE_CACHE_ENTRIES: Vec<PageCacheEntry> = Vec::new();

struct PageCacheEntry {
    path: alloc::string::String,
    offset: usize,      // file offset, aligned to PAGE_SIZE
    ppn: usize,         // physical page number
}

/// Pre-load builtin app data into the VFS page cache.
/// Called once at boot. After this, vfs_read_page serves data
/// from cache without touching the kernel heap.
pub fn page_cache_preload(name: &str, data: &[u8]) {
    let pages = (data.len() + PAGE_SIZE - 1) / PAGE_SIZE;
    unsafe {
        for i in 0..pages {
            let offset = i * PAGE_SIZE;
            let frame = match crate::mm::frame_allocator::frame_alloc() {
                Some(f) => f,
                None => return,
            };
            let pa: PhysAddr = frame.into();
            let dst = phys_to_kvirt(pa.0) as *mut u8;
            let chunk_len = core::cmp::min(PAGE_SIZE, data.len() - offset);
            // Copy data into the frame
            for j in 0..chunk_len {
                dst.add(j).write_volatile(data[offset + j]);
            }
            // Zero the rest
            for j in chunk_len..PAGE_SIZE {
                dst.add(j).write_volatile(0);
            }
            PAGE_CACHE_ENTRIES.push(PageCacheEntry {
                path: alloc::string::String::from(name),
                offset,
                ppn: frame.0,
            });
        }
    }
    crate::kprintln!(
        "[vfs-cache] preloaded: name={} size={} pages={}",
        name, data.len(), pages
    );
}

/// Look up a cached page. Returns the physical page number if found.
pub fn page_cache_lookup(path: &str, offset: usize) -> Option<PhysPageNum> {
    let aligned = offset & !(PAGE_SIZE - 1);
    // Normalize path: strip leading / and ./ for cache lookup
    let lookup = path.trim_start_matches('/').trim_start_matches("./");
    unsafe {
        for entry in PAGE_CACHE_ENTRIES.iter() {
            if entry.path.as_str() == lookup && entry.offset == aligned {
                return Some(PhysPageNum(entry.ppn));
            }
            // Also try with / prefix
            if entry.path.as_str() == path && entry.offset == aligned {
                return Some(PhysPageNum(entry.ppn));
            }
        }
    }
    None
}

