    }

    Ok(scripts)
}

/// Read a byte range [offset, offset+len) from `path` into `buf`.
/// Returns the number of bytes actually read (may be less than len at EOF).
/// Does NOT allocate on the kernel heap — caller provides the buffer.
pub fn read_file_range(path: &str, offset: usize, buf: &mut [u8]) -> Result<usize, isize> {
    // Try VFS page cache first

    // Try VFS page cache first
    let aligned = offset & !(PAGE_SIZE - 1);
    if let Some(cached_ppn) = page_cache_lookup(path, aligned) {
        let pa: PhysAddr = cached_ppn.into();
        let src = unsafe { core::slice::from_raw_parts(phys_to_kvirt(pa.0) as *const u8, PAGE_SIZE) };
        let page_off = offset - aligned;
        let copy_len = core::cmp::min(buf.len(), PAGE_SIZE - page_off);
        buf[..copy_len].copy_from_slice(&src[page_off..page_off + copy_len]);
        return Ok(copy_len);
    }

    let info = info().ok_or(err(EINVAL))?;
    let inode = lookup_path(path)?;
    crate::kprintln!("[ext4-range] path={} off={} len={} size={}", path, offset, buf.len(), inode.size);

    if inode.is_dir() {
        return Err(err(EISDIR));
    }
    if !inode.is_file() {
        return Err(err(EINVAL));
    }

    let file_size = inode.size as usize;
    if offset >= file_size || buf.is_empty() {
        return Ok(0);
    }

    let read_end = core::cmp::min(offset + buf.len(), file_size);
    let header = parse_extent_header(&inode.block)?;
    if header.depth != 0 || header.entries == 0 {
        return Ok(0);
    }

    // Process blocks in order. For blocks that are in an extent: read
    // from disk. For holes (unallocated blocks): fill with zeroes.
    // This handles sparse files correctly (e.g., test binaries with BSS).
    let total_blocks = (inode.size as usize + info.block_size - 1) / info.block_size;
    let mut sector_buf = [0u8; 512];
    let mut buf_done = 0usize;
    let sectors_per_block = info.block_size / 512;

    for blk in 0..total_blocks {
        let block_start = blk * info.block_size;
        let block_end = block_start + info.block_size;
        if block_end <= offset || block_start >= read_end {
            continue;
        }

        // Find which extent (if any) covers this logical block
        let mut phys_block: Option<usize> = None;
        for i in 0..header.entries as usize {
            let extent = parse_extent(&inode.block, i)?;
            let log_start = extent.logical_block as usize;
            let log_end = log_start + extent.len as usize;
            if blk >= log_start && blk < log_end {
                let offset_in_extent = blk - log_start;
                phys_block = Some(extent.start_block() as usize + offset_in_extent);
                break;
            }
        }

        // Read sectors: from disk if extent exists, zero-fill if hole
        for s in 0..sectors_per_block {
            let sector_off = block_start + s * 512;
            let sector_end = sector_off + 512;
            if sector_end <= offset || sector_off >= read_end {
                continue;
            }
            if let Some(pb) = phys_block {
                let disk_byte = pb * info.block_size + s * 512;
                crate::drivers::block_read_bytes(disk_byte, &mut sector_buf);
            } else {
                // Hole: fill with zeroes
                sector_buf.fill(0);
            }

            let read_start = if offset > sector_off { offset - sector_off } else { 0 };
            let read_end_in_sector = core::cmp::min(512, read_end - sector_off);
            let copy_len = read_end_in_sector - read_start;
            if copy_len > 0 && buf_done + copy_len <= buf.len() {
                buf[buf_done..buf_done + copy_len]
                    .copy_from_slice(&sector_buf[read_start..read_start + copy_len]);
                buf_done += copy_len;
            }
            if buf_done >= buf.len() || offset + buf_done >= read_end {
                return Ok(buf_done);
            }
        }
    }

    Ok(buf_done)
}

