        inode.ino,
        data.len(),
    );

    Ok(data)
}

static mut NEXT_INO: u32 = 48;

pub fn create_file(dir_path: &str, name: &str) -> Result<u32, isize> {
    let info = info().ok_or(err(EINVAL))?;
    let parent_inode = lookup_path(dir_path)?;
    if !parent_inode.is_dir() { return Err(err(ENOTDIR)); }

    let new_ino = unsafe { let ino = NEXT_INO; NEXT_INO += 1; ino };
    crate::kprintln!("[ext4] create_file: dir={} name={} new_ino={}", dir_path, name, new_ino);

    // Write new inode
    let group_id = (new_ino - 1) / info.inodes_per_group;
    let local_ino = (new_ino - 1) % info.inodes_per_group;
    let group_desc = read_group_desc(info, group_id)?;
    let inode_byte_off = group_desc.inode_table_block as usize * info.block_size
        + local_ino as usize * info.inode_size as usize;

    let mut ib = [0u8; 256];
    write_u16(&mut ib, 0x00, EXT4_S_IFREG | 0o644);
    write_u16(&mut ib, 0x02, 0);
    write_u32(&mut ib, 0x04, 0);
    write_u32(&mut ib, 0x1C, 0);
    write_u16(&mut ib, 0x28, 0xF30A);
    write_u16(&mut ib, 0x2A, 0);
    write_u16(&mut ib, 0x2C, 4);
    write_u16(&mut ib, 0x2E, 0);
    write_u32(&mut ib, 0x30, 0);
    crate::drivers::block_write_bytes(inode_byte_off, &ib);

    // Append directory entry
    let dir_block = {
        let hdr = parse_extent_header(&parent_inode.block)?;
        if hdr.depth != 0 || hdr.entries == 0 { return Err(err(EINVAL)); }
        let ext = parse_extent(&parent_inode.block, 0)?;
        ext.start_block() as usize
    };

    let mut dir_buf = Vec::new();
    dir_buf.resize(info.block_size, 0u8);
    crate::drivers::block_read_bytes(dir_block * info.block_size, &mut dir_buf);

    let name_len = name.len();
    let new_entry_size = (8 + name_len + 3) & !3;
    let mut pos = 0usize;
    loop {
        if pos + 8 > dir_buf.len() { return Err(err(EIO)); }
        let rec = read_u16(&dir_buf, pos + 4) as usize;
        if rec == 0 { return Err(err(EIO)); }
        let existing_size = (8 + (dir_buf[pos + 6] as usize + 3)) & !3;
        if rec > existing_size + new_entry_size {
            let new_pos = pos + existing_size;
            write_u16(&mut dir_buf, pos + 4, existing_size as u16);
            write_u32(&mut dir_buf, new_pos, new_ino);
            write_u16(&mut dir_buf, new_pos + 4, (rec - existing_size) as u16);
            dir_buf[new_pos + 6] = name_len as u8;
            dir_buf[new_pos + 7] = EXT4_FT_REG_FILE;
            dir_buf[new_pos + 8..new_pos + 8 + name_len].copy_from_slice(name.as_bytes());
            crate::drivers::block_write_bytes(dir_block * info.block_size, &dir_buf);
            return Ok(new_ino);
        }
        pos += rec;
    }
}

pub fn write_file(path: &str, data: &[u8]) -> Result<(), isize> {
    let info = info().ok_or(err(EINVAL))?;
    let inode = lookup_path(path)?;
    if inode.is_dir() { return Err(err(EISDIR)); }
    crate::kprintln!("[ext4] write_file: path={} ino={} size={}", path, inode.ino, data.len());

    let data_block: u32 = 4000;
    let mut block_buf = Vec::new();
    block_buf.resize(4096, 0u8);
    block_buf[..data.len()].copy_from_slice(data);
    crate::drivers::block_write_bytes(data_block as usize * 4096, &block_buf);

    // Update inode
    let group_id = (inode.ino - 1) / info.inodes_per_group;
    let local_ino = (inode.ino - 1) % info.inodes_per_group;
    let group_desc = read_group_desc(info, group_id)?;
    let inode_byte_off = group_desc.inode_table_block as usize * info.block_size
        + local_ino as usize * info.inode_size as usize;

    let mut ib = [0u8; 256];
    crate::drivers::block_read_bytes(inode_byte_off, &mut ib);
    write_u32(&mut ib, 0x04, data.len() as u32);
    write_u32(&mut ib, 0x1C, 8);
    write_u16(&mut ib, 0x2A, 1);
    write_u32(&mut ib, 0x34, 0);
    write_u16(&mut ib, 0x38, 1);
    write_u16(&mut ib, 0x3A, (data_block as u64 >> 32) as u16);

    write_u16(&mut ib, 0x3A, (data_block as u64 >> 32) as u16);
    write_u32(&mut ib, 0x3C, data_block);
    crate::drivers::block_write_bytes(inode_byte_off, &ib);

    crate::kprintln!("[ext4] write_file done");
    Ok(())
}

fn write_u16(buf: &mut [u8], off: usize, val: u16) {
    buf[off..off + 2].copy_from_slice(&val.to_le_bytes());
}

fn write_u32(buf: &mut [u8], off: usize, val: u32) {
    buf[off..off + 4].copy_from_slice(&val.to_le_bytes());
}

fn check_root_inode(info: Ext4SuperBlockInfo) -> Result<(), isize> {
    let root_group = read_group_desc(info, 0)?;

    crate::kprintln!(
        "[ext4] group desc[0]: block_bitmap={}, inode_bitmap={}, inode_table_block={}",
        root_group.block_bitmap_block,
        root_group.inode_bitmap_block,
        root_group.inode_table_block,
    );

    let root = read_inode(info, EXT4_ROOT_INO)?;

    crate::kprintln!(
        "[ext4] inode {}: mode={:#x}, size={}, blocks={}",
        root.ino,
        root.mode,
        root.size,
        root.blocks,
    );

    if !root.is_dir() {
        crate::println!("[ext4] root inode is not directory: mode={:#x}", root.mode,);
        return Err(err(EINVAL));
    }

    crate::kprintln!("[ext4] root inode ok: directory");

    scan_root_dir(info, root)?;

    Ok(())
}

fn is_test_script_name(name: &str) -> bool {
    name.ends_with("_testcode.sh")
}

fn join_path(parent: &str, name: &str) -> String {
    let mut path = String::new();

    if parent == "/" {
        path.push('/');
        path.push_str(name);
    } else {
        path.push_str(parent.trim_end_matches('/'));
        path.push('/');
        path.push_str(name);
    }

    path
}

fn find_subslice(haystack: &[u8], needle: &[u8]) -> Option<usize> {
    if needle.is_empty() {
        return Some(0);
    }

    if needle.len() > haystack.len() {
        return None;
    }

    let end = haystack.len() - needle.len();
    let mut i = 0usize;

    while i <= end {
        if &haystack[i..i + needle.len()] == needle {
            return Some(i);
        }

        i += 1;
    }

    None
}

fn parse_run_all_tests(data: &[u8]) -> Result<Vec<String>, isize> {
    let start_marker = b"tests=\"";
    let start = match find_subslice(data, start_marker) {
        Some(pos) => pos + start_marker.len(),
        None => {
            crate::kprintln!("[ext4] run-all parse failed: tests marker not found");
            return Err(err(EINVAL));
        }
    };

    let rest = &data[start..];
    let end = match find_subslice(rest, b"\"") {
        Some(pos) => pos,
        None => {
            crate::kprintln!("[ext4] run-all parse failed: closing quote not found");
            return Err(err(EINVAL));
        }
    };

    let tests_bytes = &rest[..end];
    let tests_text = match core::str::from_utf8(tests_bytes) {
        Ok(text) => text,
        Err(_) => {
            crate::kprintln!("[ext4] run-all parse failed: tests block is non-utf8");
            return Err(err(EINVAL));
        }
    };

    let mut tests = Vec::new();

    for item in tests_text.split_whitespace() {
        if item.is_empty() {
            continue;
        }

        tests.push(String::from(item));
    }

    Ok(tests)
}

pub fn find_basic_test_programs(root: &str) -> Result<Vec<Ext4BasicTestProgramInfo>, isize> {
    let basic_dir = join_path(root, "basic");
    let run_all_path = join_path(basic_dir.as_str(), "run-all.sh");

    let data = read_file(run_all_path.as_str())?;
    let names = parse_run_all_tests(data.as_slice())?;

    let mut programs = Vec::new();

    for name in names {
        let path = join_path(basic_dir.as_str(), name.as_str());

        programs.push(Ext4BasicTestProgramInfo {
            root: String::from(root),
            dir: basic_dir.clone(),
            name,
            path,
        });
    }

    Ok(programs)
}

fn parse_dir_block_entries(
    buf: &[u8],
    block_no: u64,
    block_size: usize,
) -> Result<Vec<Ext4DirEntryInfo>, isize> {
    let mut entries = Vec::new();
    let mut offset = 0usize;

    while offset + 8 <= block_size {
        let inode = read_u32(buf, offset + 0x00);
        let rec_len = read_u16(buf, offset + 0x04) as usize;
        let name_len = buf[offset + 0x06] as usize;
        let file_type = buf[offset + 0x07];

        if rec_len == 0 {
            break; // end of valid entries, rest is padding
        }

        if offset + rec_len > block_size {
            crate::println!(
                "[ext4] invalid dir entry: block={}, offset={}, rec_len={}, block_size={}",
                block_no,
                offset,
                rec_len,
                block_size,
            );
            return Err(err(EINVAL));
        }

        if inode != 0 {
            let name_start = offset + 8;
            let name_end = name_start + name_len;

            if name_end > offset + rec_len {
                crate::println!(
                    "[ext4] invalid dir name: block={}, offset={}, name_len={}, rec_len={}",
                    block_no,
                    offset,
                    name_len,
                    rec_len,
                );
                return Err(err(EINVAL));
            }

            let name = core::str::from_utf8(&buf[name_start..name_end]).map_err(|_| err(EINVAL))?;

            entries.push(Ext4DirEntryInfo {

            entries.push(Ext4DirEntryInfo {
                ino: inode,
                file_type,
                name: String::from(name),
            });
        }

        offset += rec_len;
    }

    Ok(entries)
}

fn read_dir_entries_from_inode(
    info: Ext4SuperBlockInfo,
    dir: Ext4InodeInfo,
    log_detail: bool,
) -> Result<Vec<Ext4DirEntryInfo>, isize> {
    if !dir.is_dir() {
        return Err(err(EINVAL));
    }

    let header = parse_extent_header(&dir.block)?;

    if log_detail {
        crate::kprintln!(
            "[ext4] root extent header: magic={:#x}, entries={}, max={}, depth={}, generation={}",
            header.magic,
            header.entries,
            header.max,
            header.depth,
            header.generation,
        );
    }

    if header.depth != 0 {
        crate::println!(
            "[ext4] unsupported directory extent depth: {}",
            header.depth,
        );
        return Err(err(EINVAL));
    }

    if header.entries == 0 {
        return Ok(Vec::new());
    }

    let mut entries = Vec::new();
    let mut remaining_size = dir.size as usize;
    let mut buf = [0u8; 4096];

    if info.block_size > buf.len() {
        crate::println!("[ext4] unsupported dir block size: {}", info.block_size,);
        return Err(err(EINVAL));
    }

    for i in 0..header.entries as usize {
        let extent = parse_extent(&dir.block, i)?;

        let physical_start = extent.start_block();
        let logical_start = extent.logical_block;
        let len = extent.len as usize;

        if log_detail {
            crate::kprintln!(
                "[ext4] root extent[{}]: logical={}, len={}, physical={}",
                i,
                logical_start,
                len,
                physical_start,
            );
        }

        for j in 0..len {
            if remaining_size == 0 {
                return Ok(entries);
            }

            let physical_block = physical_start + j as u64;
            let offset = physical_block as usize * info.block_size;

            let ret = crate::drivers::block_read_bytes(offset, &mut buf[..info.block_size]);

            if ret != info.block_size as isize {
                crate::println!(
                    "[ext4] read dir block failed: physical_block={}, offset={:#x}, ret={}",
                    physical_block,
                    offset,
                    ret,
                );
                return Err(err(EIO));
            }

            if log_detail {
                crate::kprintln!(
                    "[ext4] root dir block: logical={}, physical={}, offset={:#x}",
                    logical_start + j as u32,
                    physical_block,
                    offset,
                );
            }

            let block_entries =
                parse_dir_block_entries(&buf[..info.block_size], physical_block, info.block_size)?;

            for entry in block_entries {
                entries.push(entry);
            }

            if remaining_size > info.block_size {
                remaining_size -= info.block_size;
            } else {
                remaining_size = 0;
            }
        }
    }

    Ok(entries)
}

