pub fn sys_clone(flags: usize, stack: usize, ptid: usize, tls: usize, ctid: usize) -> isize {
    const SIGCHLD: usize = 17;
    const CSIGNAL_MASK: usize = 0xff;
    const CLONE_CHILD_CLEARTID: usize = 0x0020_0000;
    const CLONE_CHILD_SETTID: usize = 0x0100_0000;
    const FORK_LIKE_ALLOWED: usize = CLONE_CHILD_CLEARTID | CLONE_CHILD_SETTID;

    crate::kprintln!(
        "[sys_clone] flags={:#x}, stack={:#x}, ptid={:#x}, tls={:#x}, ctid={:#x}",
        flags,
        stack,
        ptid,
        tls,
        ctid,
    );

    if flags == 0 || flags == SIGCHLD {
        crate::task::clone_current_user_process(stack)
    } else if (flags & CSIGNAL_MASK) == SIGCHLD
        && (flags & !(CSIGNAL_MASK | FORK_LIKE_ALLOWED)) == 0
    {
        crate::task::clone_current_user_process(stack)
    } else {
        crate::println!("[sys_clone] unsupported flags={:#x}", flags,);
        err(EINVAL)
    }
}

pub fn sys_waitpid(pid: isize, exit_code_ptr: usize, options: usize) -> isize {
    const WNOHANG: usize = 1;
    crate::kprintln!(
        "[sys_waitpid] pid={}, exit_code_ptr={:#x}, options={:#x}",
        pid, exit_code_ptr, options,
    );

    let child_pid = if pid == -1 {
        None
    } else if pid >= 0 {
        Some(pid as usize)
    } else {
        crate::println!("[sys_waitpid] invalid pid={}", pid);
        return err(EINVAL);
    };

    let result = crate::task::wait_zombie_child_for_current(child_pid);

    match result {
        crate::task::WaitResult::Reaped { pid, exit_code } => {
            crate::kprintln!(
                "[sys_waitpid] reaped child: pid={}, exit_code={}",
                pid,
                exit_code,
            );

            if exit_code_ptr != 0 {
                let wait_status = (exit_code & 0xff) << 8;
                let bytes = wait_status.to_ne_bytes();

                let ok = crate::task::with_current_memory_set(|space| {
                    space.copy_to_user_checked(exit_code_ptr, &bytes)
                });

                if !ok {
                    crate::println!("[sys_waitpid] failed to write exit_code");
                    return err(EFAULT);
                }
            }

            pid as isize
        }

        crate::task::WaitResult::NoZombie => {
            if options & WNOHANG != 0 {
                return 0; // non-blocking: no child exited yet
            }
            crate::kprintln!("[sys_waitpid] no zombie child yet, block current");
            crate::task::block_current_on_child_exit_wait();
        }

        crate::task::WaitResult::NoChild => {
            if options & WNOHANG != 0 {
                0 // non-blocking poll: no child exited
            } else if child_pid.is_some() {
                err(ECHILD) // specific pid, blocking: no such child
            } else {
                0 // wait(-1): no children, but ASH uses this for job control
            }
        }
    }
}

fn copy_user_cstr(ptr: usize, buf: &mut [u8]) -> Result<&str, isize> {
    if ptr == 0 || buf.is_empty() {
        return Err(err(EFAULT));
    }

    let mut len = 0usize;

    while len + 1 < buf.len() {
        let ok = crate::task::with_current_memory_set(|space| {
            space.copy_from_user(ptr + len, &mut buf[len..len + 1])
        });

        if !ok {
            crate::println!(
                "[sys_execve] failed to read path byte: ptr={:#x}, offset={}",
                ptr,
                len,
            );
            return Err(err(EFAULT));
        }

        if buf[len] == 0 {
            return core::str::from_utf8(&buf[..len]).map_err(|_| err(EINVAL));
        }

        len += 1;
    }

    crate::println!(
        "[sys_execve] path too long or missing nul: ptr={:#x}, max_len={}",
        ptr,
        buf.len(),
    );

    Err(err(ENAMETOOLONG))
}

