pub fn sys_gettimeofday(tv_ptr: usize, _tz_ptr: usize) -> isize {
    if tv_ptr == 0 {
        return err(EFAULT);
    }

    const TIME_FREQ: usize = 12_500_000;
    let now = crate::arch::read_time();
    let sec = now / TIME_FREQ;
    let usec = (now % TIME_FREQ) * 1_000_000 / TIME_FREQ;

    let mut tv = [0u8; 16];
    write_u64(&mut tv, 0, sec as u64);
    write_u64(&mut tv, 8, usec as u64);

    let ok = crate::task::with_current_memory_set(|space| space.copy_to_user_checked(tv_ptr, &tv));

    if ok { 0 } else { err(EFAULT) }
}

pub fn sys_nanosleep(req_ptr: usize, rem_ptr: usize) -> isize {
    if req_ptr == 0 {
        return err(EFAULT);
    }

    let mut req = [0u8; 16];
    let ok = crate::task::with_current_memory_set(|space| space.copy_from_user(req_ptr, &mut req));
    if !ok {
        return err(EFAULT);
    }

    const TIME_FREQ: usize = 12_500_000;
    let sec = read_u64(req.as_slice(), 0) as usize;
    let nsec = read_u64(req.as_slice(), 8) as usize;
    let ticks = sec
        .saturating_mul(TIME_FREQ)
        .saturating_add(nsec.saturating_mul(TIME_FREQ) / 1_000_000_000);
    let wake = crate::arch::read_time().saturating_add(ticks);

    while crate::arch::read_time() < wake {
        core::hint::spin_loop();
    }

    if rem_ptr != 0 {
        let zero = [0u8; 16];
        let _ = crate::task::with_current_memory_set(|space| {
            space.copy_to_user_checked(rem_ptr, &zero)
        });
    }

    0
}

pub fn sys_times(tms_ptr: usize) -> isize {
    let ticks = crate::arch::read_time() / crate::arch::timer_interval();

    if tms_ptr != 0 {
        let mut tms = [0u8; 32];
        write_u64(&mut tms, 0, ticks as u64);
        write_u64(&mut tms, 8, 0);
        write_u64(&mut tms, 16, 0);
        write_u64(&mut tms, 24, 0);

        let ok =
            crate::task::with_current_memory_set(|space| space.copy_to_user_checked(tms_ptr, &tms));
        if !ok {
            return err(EFAULT);
        }
    }

    ticks as isize
}

pub fn sys_clock_gettime(clk_id: usize, tp: usize) -> isize {
    if tp == 0 { return err(EFAULT); }
    const CLOCK_REALTIME: usize = 0;
    const CLOCK_MONOTONIC: usize = 1;
    if clk_id != CLOCK_REALTIME && clk_id != CLOCK_MONOTONIC { return err(EINVAL); }

    let now = crate::arch::read_time();
    const FREQ: usize = 12_500_000;
    let sec = now / FREQ;
    let nsec = (now % FREQ) * 1_000_000_000 / FREQ;
    let mut ts = [0u8; 16];
    write_u64(&mut ts, 0, sec as u64);
    write_u64(&mut ts, 8, nsec as u64);
    if crate::task::with_current_memory_set(|s| s.copy_to_user_checked(tp, &ts)) { 0 } else { err(EFAULT) }
}

