pub fn sys_write(fd: usize, buf: usize, len: usize) -> isize {
    let mut copied = 0;
    let mut tmp = [0u8; 256];

    while copied < len {
        let n = core::cmp::min(tmp.len(), len - copied);

        let ok = crate::task::with_current_memory_set(|space| {
            space.copy_from_user(buf + copied, &mut tmp[..n])
        });

        if !ok {
            return err(EFAULT);
        }

        if fd == 1 || fd == 2 {
            for &ch in &tmp[..n] {
                crate::drivers::serial::Serial::putchar(ch);
            }
        } else {
            let task = crate::task::current();
            let Some(file) = task.user_file_mut(fd) else {
                return err(EBADF);
            };

            if file.is_dev_null {
                copied += n;
                continue; // /dev/null: discard all writes silently
            }

            if file.is_dir {
                return err(EINVAL);
            }

            if file.is_stdout {
                for &ch in &tmp[..n] {
                    crate::drivers::serial::Serial::putchar(ch);
                }
                copied += n;
                continue;
            }

            if let Some(pipe_id) = file.pipe_id {
                if !file.pipe_write {
                    return err(EBADF);
                }
                unsafe {
                    if let Some(pipe) = PIPE_BUFFERS.get_mut(pipe_id) {
                        pipe.extend_from_slice(&tmp[..n]);
                    } else {
                        return err(EBADF);
                    }
                }
                copied += n;
                continue;
            }

            file.data.extend_from_slice(&tmp[..n]);
            file.offset = file.data.len();
            remember_created_file(file.path.as_str(), file.data.as_slice());
        }

        copied += n;
    }

    len as isize
}

pub fn sys_read(fd: usize, buf: usize, len: usize) -> isize {
    let task = crate::task::current();
    let Some(file) = task.user_file_mut(fd) else {
        return err(EBADF);
    };

    if file.is_dev_null {
        return 0; // /dev/null: always EOF on read
    }
    if file.is_dir {
        return err(EINVAL);
    }
    if file.is_stdout {
        return err(EBADF);
    }

    // Lazy-load EXT4 file data on first read
    if file.on_disk && file.data.is_empty() {
        match read_file_from_rootfs(file.path.as_str()) {
            Ok(d) => file.data = d,
            Err(_) => return err(EIO),
        }
    }
    if let Some(pipe_id) = file.pipe_id {
        if !file.pipe_read {
            return err(EBADF);
        }
        let chunk = loop {
            let chunk = unsafe {
                let Some(pipe) = PIPE_BUFFERS.get_mut(pipe_id) else {
                    return err(EBADF);
                };
                let n = core::cmp::min(len, pipe.len());
                let chunk = pipe[..n].to_vec();
                pipe.drain(0..n);
                chunk
            };

            if !chunk.is_empty() || crate::task::ready_count() == 0 {
                break chunk;
            }

            crate::task::yield_current();
        };

        if chunk.is_empty() {
            return 0;
        }

        let ok = crate::task::with_current_memory_set(|space| {
            space.copy_to_user_checked(buf, chunk.as_slice())
        });

        return if ok {
            chunk.len() as isize
        } else {
            err(EFAULT)
        };
    }

    let n = core::cmp::min(len, file.data.len().saturating_sub(file.offset));
    let start = file.offset;
    let end = start + n;
    let chunk = file.data[start..end].to_vec();
    file.offset = end;

    let ok = crate::task::with_current_memory_set(|space| {
        space.copy_to_user_checked(buf, chunk.as_slice())
    });

    if !ok {
        return err(EFAULT);
    }

    n as isize
}

pub fn sys_close(fd: usize) -> isize {
    if crate::task::current().close_user_file(fd) {
