pub fn block_read_bytes(offset: usize, buf: &mut [u8]) -> isize {
    #[cfg(feature = "arch_riscv64")]
    { virtio_mmio::read_bytes(offset, buf) }
    #[cfg(feature = "arch_loongarch64")]
    { virtio_pci::read_bytes(offset, buf) }
}

pub fn block_write_bytes(offset: usize, buf: &[u8]) -> isize {
    #[cfg(feature = "arch_riscv64")]
    {
        let mut done = 0;
        let mut sec_buf = [0u8; 512];
        let end = offset + buf.len();
        while offset + done < end {
            let cur = offset + done;
            let s = cur / 512;
            let off = cur % 512;
            let remaining = end - cur;
            if off == 0 && remaining >= 512 {
                let batch = core::cmp::min(remaining / 512, 8) * 512;
                let r = virtio_mmio::write_block(s, &buf[done..done + batch]);
                if r < 0 { return r; }
                done += batch;
            } else {
                let n = core::cmp::min(512 - off, remaining);
                // read-modify-write
                virtio_mmio::read_block(s, &mut sec_buf);
                sec_buf[off..off + n].copy_from_slice(&buf[done..done + n]);
                let r = virtio_mmio::write_block(s, &sec_buf);
                if r < 0 { return r; }
                done += n;
            }
        }
        done as isize
    }
    #[cfg(feature = "arch_loongarch64")]
    {
        let mut done = 0;
        let mut sec_buf = [0u8; 512];
        let end = offset + buf.len();
        while offset + done < end {
            let cur = offset + done;
            let s = cur / 512;
            let off = cur % 512;
            let remaining = end - cur;
            if off == 0 && remaining >= 512 {
                let batch = core::cmp::min(remaining / 512, 8) * 512;
                let r = virtio_pci::write_block(s, &buf[done..done + batch]);
                if r < 0 { return r; }
                done += batch;
            } else {
                let n = core::cmp::min(512 - off, remaining);
                virtio_pci::read_block(s, &mut sec_buf);
                sec_buf[off..off + n].copy_from_slice(&buf[done..done + n]);
                let r = virtio_pci::write_block(s, &sec_buf);
                if r < 0 { return r; }
                done += n;
            }
        }
        done as isize
    }
}

use core::fmt::{self, Write};

#[cfg(feature = "arch_loongarch64")]
const UART0: usize = 0x8000_0000_1fe0_01e0;

#[cfg(not(feature = "arch_loongarch64"))]
const UART0: usize = 0x1000_0000;

pub struct Serial;

impl Serial {
    pub fn putchar(c: u8) {
        unsafe {
            #[cfg(feature = "arch_loongarch64")]
            while core::ptr::read_volatile((UART0 + 5) as *const u8) & (1 << 5) == 0 {}

            core::ptr::write_volatile(UART0 as *mut u8, c);
        }
    }

    pub fn puts(s: &str) {
        for b in s.bytes() {
            if b == b'\n' {
                Self::putchar(b'\r');
            }
            Self::putchar(b);
        }
    }
}

impl Write for Serial {
    fn write_str(&mut self, s: &str) -> fmt::Result {
        Serial::puts(s);
        Ok(())
    }
}

pub fn _print(args: fmt::Arguments) {
    use core::fmt::Write;
    let _ = Serial.write_fmt(args);
}

