pub use initproc::{UserApp, find_user_app, list_user_apps, load_initproc, load_user_app};
use crate::mm::memory_set::MemorySet;

pub struct UserApp {
    pub name: &'static str,
    pub data: &'static [u8],
}

#[cfg(feature = "arch_riscv64")]
static USER_APPS: &[UserApp] = &[
    UserApp { name: "initproc",  data: include_bytes!("../../user/riscv64/initproc.elf") },
    UserApp { name: "childproc", data: include_bytes!("../../user/riscv64/childproc.elf") },
];

#[cfg(feature = "arch_loongarch64")]
static USER_APPS: &[UserApp] = &[
    UserApp { name: "initproc",  data: include_bytes!("../../user/loongarch64/initproc.elf") },
    UserApp { name: "childproc", data: include_bytes!("../../user/loongarch64/childproc.elf") },
];

pub fn preload_page_cache() {
    for app in USER_APPS.iter() {
        crate::fs::ext4::page_cache_preload(app.name, app.data);
    }
}

pub fn list_user_apps() {
    crate::kprintln!("[loader] user apps: count={}", USER_APPS.len());
    for app in USER_APPS.iter() {
        crate::kprintln!("[loader] user app: name={}, size={:#x}", app.name, app.data.len());
    }
    preload_page_cache();
}

pub fn find_user_app(name: &str) -> Option<&'static UserApp> {
    let app_name = normalize_builtin_app_name(name);
    USER_APPS.iter().find(|app| app.name == app_name)
}

pub fn load_user_app(name: &str) -> Option<(MemorySet, usize, usize, usize)> {
    let app = find_user_app(name)?;
    crate::kprintln!("[loader] load user app: path={}, name={}, size={:#x}", name, app.name, app.data.len());
    Some(crate::loader::elf::load_elf(app.data))
}

pub fn load_initproc() -> (MemorySet, usize, usize, usize) {
    load_user_app("initproc").expect("[loader] initproc app not found")
}

fn normalize_builtin_app_name(path: &str) -> &str {
    let mut name = path;
    while name.starts_with('/') { name = &name[1..]; }
    while name.starts_with("./") { name = &name[2..]; }
    if let Some(rest) = name.strip_prefix("bin/") { name = rest; }
    name
}

