const EI_CLASS: usize = 4;
const EI_DATA: usize = 5;

const ELFCLASS64: u8 = 2;
const ELFDATA2LSB: u8 = 1;

const ET_EXEC: u16 = 2;
const ET_DYN: u16 = 3;

const ELF_HEADER_SIZE: usize = 64;
const ELF64_PHENTSIZE: usize = 56;

const PT_LOAD: u32 = 1;
const PT_INTERP: u32 = 3;
const PT_TLS: u32 = 7;

const PF_X: u32 = 1;
const PF_W: u32 = 2;
const PF_R: u32 = 4;

// const USER_STACK_TOP: usize = 0x0000_0000_8000_0000;
// const USER_STACK_SIZE: usize = 0x20_000;

/*
EI_CLASS       ELF header 中 e_ident[4]，表示 ELF32 / ELF64
EI_DATA        ELF header 中 e_ident[5]，表示小端 / 大端
ELFCLASS64     64 位 ELF
ELFDATA2LSB    little-endian
ET_EXEC        可执行文件
ELF_HEADER_SIZE ELF64 header 最小大小，64 字节
ELF64_PHENTSIZE ELF64 Program Header 标准大小，56 字节
*/

fn read_u16(data: &[u8], off: usize) -> Option<u16> {
    let end = off.checked_add(2)?;
    let bytes = data.get(off..end)?;
    Some(u16::from_le_bytes([bytes[0], bytes[1]]))
}

fn read_u32(data: &[u8], off: usize) -> Option<u32> {
    let end = off.checked_add(4)?;
    let bytes = data.get(off..end)?;
    Some(u32::from_le_bytes([bytes[0], bytes[1], bytes[2], bytes[3]]))
}

fn read_u64(data: &[u8], off: usize) -> Option<u64> {
    let end = off.checked_add(8)?;
    let bytes = data.get(off..end)?;
    Some(u64::from_le_bytes([
        bytes[0], bytes[1], bytes[2], bytes[3], bytes[4], bytes[5], bytes[6], bytes[7],
    ]))
}

/// Load an ELF from the EXT4 disk via VFS page cache.
/// Reconstructs file data from cached pages into a static buffer,
/// then delegates to the proven load_elf_with_argv.
pub fn load_elf_from_disk(
    path: &str,
    argv: &[&[u8]],
) -> Result<(MemorySet, usize, usize, usize), isize> {
    // Primary: static buffer → load_elf_with_argv (proven, fast).
    // Fallback: streaming (no size limit, handles any file).
    static mut BUF: [[u8; 0x400000]; 3] = [[0u8; 0x400000]; 3];
    static mut BIDX: u8 = 0;
    let idx = unsafe { let i = BIDX; BIDX = (i + 1) % 3; i as usize };
    let buf = unsafe { &mut BUF[idx][..] };
    let mut off = 0usize;
    while off < buf.len() {
        let chunk = 4096;
        if off + chunk > buf.len() { break; }
        match crate::fs::ext4::read_file_range(path, off, &mut buf[off..off+chunk]) {
            Ok(0) => break,
            Ok(n) => off += n,
            Err(_) => break,
        }
    }
    if off > 0 && buf[..4] == [0x7f, b'E', b'L', b'F'] {
        return Ok(load_elf_with_argv(&buf[..off], argv));
    }
    // Buffer too small or corrupted — fall back to streaming
    load_elf_from_disk_streaming(path, argv)
}

#[allow(dead_code)]
pub fn load_elf_from_disk_streaming(
    path: &str,
    argv: &[&[u8]],
) -> Result<(MemorySet, usize, usize, usize), isize> {
    // Read ELF header (first 64 bytes) + program headers into a small stack buffer
    let mut hdr_buf = [0u8; 1024]; // enough for header + typical phdrs
    let hdr_len = crate::fs::ext4::read_file_range(path, 0, &mut hdr_buf)
        .map_err(|_| crate::syscall::errno::err(crate::syscall::errno::ENOEXEC))?;
    if hdr_len < 64 {
        crate::println!("[elf-disk] header too short: {} bytes", hdr_len);
        return Err(crate::syscall::errno::err(crate::syscall::errno::ENOEXEC));
    }

    let header = parse_elf_header(&hdr_buf)
        .ok_or(crate::syscall::errno::err(crate::syscall::errno::ENOEXEC))?;

    let phdr_end = header.phoff + header.phnum * header.phentsize;
    if phdr_end > hdr_buf.len() {
        crate::println!("[elf-disk] phdrs dont fit in buffer: {} > {}", phdr_end, hdr_buf.len());
        return Err(crate::syscall::errno::err(crate::syscall::errno::ENOEXEC));
    }

    crate::kprintln!(
        "[elf-disk] loading: path={} type={} entry={:#x} phoff={:#x} phnum={}",
        path,
        elf_type_name(header.e_type),
        header.entry,
        header.phoff,
        header.phnum,
    );

    let mut memory_set = MemorySet::new_user_bare();

    let load_base: usize = if header.e_type == ET_DYN { 0 } else { 0 };
    let user_stack_va_bottom = USER_STACK_TOP
        .checked_sub(USER_STACK_SIZE)
        .expect("[elf] user stack bottom underflow");

    let mut max_load_end = 0usize;
    let mut first_load_vaddr: usize = 0;

    for i in 0..header.phnum {
        let ph_off = header.phoff + i * header.phentsize;
        let ph = parse_program_header(&hdr_buf, ph_off)
            .expect("[elf] bad program header");

        if ph.p_type != PT_LOAD || ph.memsz == 0 {
            continue;
        }

        if first_load_vaddr == 0 {
            first_load_vaddr = load_base + ph.vaddr;
        }

        let start_va = load_base + ph.vaddr;
        let end_va = ph.vaddr + ph.memsz;

        if end_va > max_load_end {
            max_load_end = end_va;
        }

        let perm = flags_to_perm(ph.flags);
        memory_set.push_area(MapArea::new(
            VirtAddr(start_va),
            VirtAddr(end_va),
            MapType::Framed,
            perm,
            MapAreaType::ElfLoad,
        ));

        // Read segment data directly from disk into the user page frames
        if ph.filesz > 0 {
            let file_end = ph.offset + ph.filesz;
            let mut disk_off = ph.offset;
            let mut va = start_va;

            while disk_off < file_end {
                let page_off = va % PAGE_SIZE;
                let chunk = core::cmp::min(PAGE_SIZE - page_off, file_end - disk_off);

                // Translate VA to PA (page should already be mapped by push_area)
                let pa = memory_set.translate_va(va).ok_or(
                    crate::syscall::errno::err(crate::syscall::errno::ENOMEM)
                )?;

                let phys_buf = unsafe {
                    core::slice::from_raw_parts_mut(
                        phys_to_kvirt(pa) as *mut u8,
                        PAGE_SIZE,
                    )
                };

                // Use copy_to_user for byte-for-byte identical behavior to builtin path
                let n = if let Some(cached_ppn) = crate::fs::ext4::page_cache_lookup(path, disk_off) {
                    let cached_pa: crate::mm::address::PhysAddr = cached_ppn.into();
                    let src_slice = unsafe {
                        core::slice::from_raw_parts(
                            phys_to_kvirt(cached_pa.0) as *const u8,
                            PAGE_SIZE,
                        )
                    };
                    let off_in_page = disk_off & (PAGE_SIZE - 1);
                    let copy_len = core::cmp::min(chunk, PAGE_SIZE - off_in_page);
                    // Use copy_to_user (same function as builtin path)
                    memory_set.copy_to_user(va, &src_slice[off_in_page..off_in_page + copy_len]);
                    copy_len
                } else {
                    crate::fs::ext4::read_file_range(path, disk_off, &mut phys_buf[page_off..page_off + chunk])
                        .map_err(|_| crate::syscall::errno::err(crate::syscall::errno::EIO))?
                };

                };
                if n == 0 { break; } // EOF or error
                disk_off += n;
                va += n;
            }
        }

        // Zero-fill BSS
        if ph.memsz > ph.filesz {
            let zero_start = start_va + ph.filesz;
            memory_set.zero_user(zero_start, ph.memsz - ph.filesz);
        }

        crate::kprintln!(
            "[elf] disk LOAD: va={:#x}..{:#x} filesz={:#x} memsz={:#x}",
            start_va, end_va, ph.filesz, ph.memsz
        );
    }

    let heap_start = VirtAddr(max_load_end).ceil().start_address().0;
    memory_set.init_user_heap(heap_start);
    memory_set.mmap_top = heap_start + 0x40_0000; // 4MB above heap

    // Stack setup: use generous physical allocation so large ELFs
    // like busybox don't overflow their initial stack.
    if memory_set.stack_alloc < USER_STACK_SIZE {
        memory_set.stack_alloc = USER_STACK_SIZE;
    }

    let stack_va_bottom = USER_STACK_TOP - USER_STACK_SIZE;
    let stack_phys_bottom = USER_STACK_TOP - memory_set.stack_alloc;
    let stack_map_top = USER_STACK_TOP + 0x1000;

    memory_set.push_area(MapArea::new(
        VirtAddr(stack_phys_bottom),
        VirtAddr(stack_map_top),
        MapType::Framed,
        MapPermission::user_rw(),
        MapAreaType::UserStack,
    ));

    // Build argv/envp on user stack (same as load_elf_with_argv)
    let argc = argv.len();
    let strs_total: usize = argv.iter().map(|s| s.len() + 1).sum();
    let extras = 16 + 8;
    let ptrs_size = (argc + 1 + 1) * 8;
    let str_base_off = (ptrs_size + 8 + strs_total + extras + 15) & !15;
    let total = str_base_off;
    let user_sp = USER_STACK_TOP.checked_sub(total)
        .expect("[elf] user stack underflow");

    let mut pos = user_sp;
    memory_set.copy_to_user(pos, &(argc as u64).to_le_bytes());
    pos += 8;
    let str_base = user_sp + ptrs_size + 8;
    let mut str_off = 0usize;
    for s in argv {
        let ptr = (str_base + str_off) as u64;
        memory_set.copy_to_user(pos, &ptr.to_le_bytes());
        pos += 8;
        str_off += s.len() + 1;
    }
    memory_set.copy_to_user(pos, &[0u8; 8]);
    pos += 8;
    memory_set.copy_to_user(pos, &[0u8; 8]);

    // AT_RANDOM + AT_PLATFORM
    let auxv_pos = str_base + strs_total;
    let auxv_pos = (auxv_pos + 15) & !15;
    let random_bytes: [u8; 16] = [0xde,0xad,0xbe,0xef,0xca,0xfe,0xba,0xbe,0x01,0x23,0x45,0x67,0x89,0xab,0xcd,0xef];
    let random_ptr = auxv_pos as u64;
    memory_set.copy_to_user(auxv_pos, &random_bytes);
    let plt_pos = auxv_pos + 16;
    #[cfg(feature = "arch_riscv64")]
    let platform_str = b"riscv64\0";
    #[cfg(feature = "arch_loongarch64")]
    let platform_str = b"loongarch64\0";
    #[cfg(not(any(feature = "arch_riscv64", feature = "arch_loongarch64")))]
    let platform_str = b"unknown\0";
    let platform_ptr = plt_pos as u64;
    memory_set.copy_to_user(plt_pos, platform_str);
    let auxv_start = plt_pos + platform_str.len();
    let auxv_start = (auxv_start + 15) & !15;

    let at_phdr = first_load_vaddr.saturating_add(header.phoff);
    let at_entry = load_base + header.entry;
    let auxv: [u64; 32] = [
        6, 4096, 3, at_phdr as u64, 4, 56, 5, header.phnum as u64,
        8, 0, 9, at_entry as u64, 11, 0, 12, 0, 13, 0, 14, 0,
        15, platform_ptr, 16, 0, 17, 100, 23, 0, 25, random_ptr,
        0, 0,  // AT_NULL terminator — required by ABI!
    ];
    let auxv_bytes = unsafe {
        core::slice::from_raw_parts(auxv.as_ptr() as *const u8, auxv.len() * 8)
    };
    memory_set.copy_to_user(auxv_start, auxv_bytes);

    // argv strings
    let mut str_pos = str_base;
    for s in argv {
        memory_set.copy_to_user(str_pos, s);
        memory_set.write_byte(str_pos + s.len(), 0);
        str_pos += s.len() + 1;
    }

    let effective_entry = at_entry;
    crate::kprintln!("[elf] disk load done: path={} sp={:#x} entry={:#x}", path, user_sp, effective_entry);

    Ok((memory_set, effective_entry, user_sp, 0))
}

pub fn load_elf(data: &[u8]) -> (MemorySet, usize, usize, usize) {
    load_elf_with_argv(data, &[])
}

pub fn load_elf_with_argv(data: &[u8], argv: &[&[u8]]) -> (MemorySet, usize, usize, usize) {
    crate::kprintln!("[elf] load elf begin argc={}", argv.len());

    let header = parse_elf_header(data).expect("[elf] bad elf header");

    crate::kprintln!(
        "[elf] header: type={}, entry={:#x}, phoff={:#x}, phentsize={}, phnum={}",
        elf_type_name(header.e_type),
        header.entry,
        header.phoff,
        header.phentsize,
        header.phnum
    );

    let mut memory_set = MemorySet::new_user_bare();

    // ET_DYN (PIE) programs: use load_base=0 for now (same behaviour as before
    // PT_INTERP changes).  The interpreter itself is loaded at a distinct high address
    // (0x7F00_0000_0000) so it won't overlap.
    let load_base: usize = if header.e_type == ET_DYN { 0 } else { 0 };

    let user_stack_va_bottom = USER_STACK_TOP
        .checked_sub(USER_STACK_SIZE)
        .expect("[elf] user stack bottom underflow");

    let mut max_load_end = 0usize;
    let mut first_load_vaddr: usize = 0;
