pub fn read_block(sector: usize, buf: &mut [u8]) -> isize {
    let base = unsafe { BLOCK_BASE };

    if base == 0 {
        return err(ENODEV);
    }

    let read_len = buf.len();
    if read_len == 0 || read_len % 512 != 0 {
        return err(EIO);
    }

    unsafe {
        REQ.req_type = VIRTIO_BLK_T_IN;
        REQ.reserved = 0;
        REQ.sector = sector as u64;
        STATUS = 0xff;

        // Use BATCH_BUF for reads > 512, DATA_BUF otherwise
        let (data_ptr, data_size) = if read_len <= 512 {
            for byte in DATA_BUF.iter_mut() { *byte = 0; }
            (DATA_BUF.as_ptr(), 512usize)
        } else {
            for byte in BATCH_BUF[..read_len].iter_mut() { *byte = 0; }
            (BATCH_BUF.as_ptr(), read_len)
        };

        QUEUE.desc[0] = VirtqDesc {
            addr: core::ptr::addr_of!(REQ) as u64,
            len: core::mem::size_of::<VirtioBlkReq>() as u32,
            flags: DESC_F_NEXT,
            next: 1,
        };

        QUEUE.desc[1] = VirtqDesc {
            addr: data_ptr as u64,
            len: data_size as u32,
            flags: DESC_F_NEXT | DESC_F_WRITE,
            next: 2,
        };

        QUEUE.desc[2] = VirtqDesc {
            addr: core::ptr::addr_of!(STATUS) as u64,
            len: 1,
            flags: DESC_F_WRITE,
            next: 0,
        };

        let avail_idx = QUEUE.avail.idx;
        QUEUE.avail.ring[(avail_idx as usize) % QUEUE_SIZE] = 0;

        compiler_fence(Ordering::SeqCst);

        QUEUE.avail.idx = avail_idx.wrapping_add(1);

        compiler_fence(Ordering::SeqCst);

        write32(base, MMIO_QUEUE_NOTIFY, 0);

        while QUEUE.used.idx == LAST_USED_IDX {
            core::hint::spin_loop();
        }

        LAST_USED_IDX = QUEUE.used.idx;

        compiler_fence(Ordering::SeqCst);

        let interrupt_status = read32(base, MMIO_INTERRUPT_STATUS);
        if interrupt_status != 0 {
            write32(base, MMIO_INTERRUPT_ACK, interrupt_status);
        }

        if STATUS != VIRTIO_BLK_S_OK {
            crate::println!(
                "[virtio-blk] read failed: sector={}, status={}",
                sector,
                STATUS,
            );
            return err(EIO);
        }

        if read_len <= 512 {
            buf.copy_from_slice(&DATA_BUF[..read_len]);
        } else {
            buf.copy_from_slice(&BATCH_BUF[..read_len]);
        }
    }

    crate::kprintln!("[virtio-blk] read block: sector={} len={}", sector, read_len);

    0
}

