pub fn sys_futex(addr: usize, op: usize, val: usize) -> isize {
    // Single-thread futex: always succeed immediately
    // In a single-threaded env, locks are never truly contended between threads;
    // the only contention is self-deadlock within musl's __lock protocol,
    // which uses 3-state locks (0/1/2) and sets state to 2 before futex wait.
    // We simulate an immediate wake by reading the current value and checking.
    if (op & 0x7f) == 0 { // FUTEX_WAIT
        let mut cur = [0u8; 4];
        if crate::task::with_current_memory_set(|s| s.copy_from_user(addr, &mut cur)) {
            let cur_val = u32::from_le_bytes(cur) as usize;
            if cur_val == val {
                // Lock is in "waiting" state. Pretend we woke up by
                // changing the lock back to "locked" (state 1).
                let new_val = (val - 1).max(0) as u32;
                let _ = crate::task::with_current_memory_set(|s| {
                    s.copy_to_user_checked(addr, &new_val.to_le_bytes())
                });
                0
            } else {
                0 // already unlocked
            }
        } else {
            err(crate::syscall::errno::EFAULT)
        }
    } else {
        0 // FUTEX_WAKE
    }
}

