pub(crate) fn normalize_path(dirfd: isize, path: &str) -> String {
    const AT_FDCWD: isize = -100;

    let path = path.strip_prefix("./").unwrap_or(path);
    if path.starts_with('/') {
        return normalize_absolute_path(path);
    }

    if dirfd >= 3 {
        if let Some(dir) = crate::task::current().user_file(dirfd as usize) {
            if dir.is_dir {
                return normalize_absolute_path(join_path(dir.path.as_str(), path).as_str());
            }
        }
        return String::from("");
    }

    if dirfd == AT_FDCWD || dirfd < 0 {
        normalize_absolute_path(join_path(crate::task::current().cwd(), path).as_str())
    } else {
        normalize_absolute_path(join_path(crate::task::current().cwd(), path).as_str())
    }
}

