fn normalize_absolute_path(path: &str) -> String {
    let mut parts: Vec<&str> = Vec::new();

    for part in path.split('/') {
        if part.is_empty() || part == "." {
            continue;
        }
        if part == ".." {
            parts.pop();
        } else {
            parts.push(part);
        }
    }

    let mut out = String::from("/");
    for (idx, part) in parts.iter().enumerate() {
        if idx > 0 {
            out.push('/');
        }
        out.push_str(part);
    }
    out
}

fn dir_exists(path: &str) -> bool {
    if path.is_empty() {
        return false;
    }

    if rootfs_dir_exists(path) {
        return true;
    }

    unsafe { CREATED_DIRS.iter().any(|dir| dir.as_str() == path) }
}

fn remember_created_file(path: &str, data: &[u8]) {
    if path.is_empty() || path == "stdout" || path == "pipe" {
        return;
    }

    unsafe {
        if let Some(file) = CREATED_FILES
            .iter_mut()
            .find(|file| file.path.as_str() == path)
        {
            file.data.clear();
            file.data.extend_from_slice(data);
            return;
        }

        CREATED_FILES.push(CreatedFile {
            path: String::from(path),
            data: data.to_vec(),
        });
    }
}

fn read_virtual_file(path: &str) -> Result<Vec<u8>, isize> {
    if path_deleted(path) {
        return Err(err(ENOENT));
    }

    unsafe {
        if let Some(file) = CREATED_FILES
            .iter()
            .find(|file| file.path.as_str() == path)
        {
            return Ok(file.data.clone());
        }
    }

    // For EXT4 files: check existence without reading content.
    // Lazy-load happens in sys_read, streaming happens in exec_elf_from_disk.
    if ext4_file_exists(path) {
        return Ok(Vec::new());
    }

    // Try builtin apps
    if crate::loader::find_user_app(path).is_some() {
        return Ok(Vec::new());
    }

    Err(err(ENOENT))
}

fn path_deleted(path: &str) -> bool {
    unsafe { DELETED_PATHS.iter().any(|deleted| deleted.as_str() == path) }
}

fn dir_entry_names(path: &str) -> Vec<String> {
    let mut names = Vec::new();

    names.extend(rootfs_dir_entry_names(path));

    unsafe {
        for dir in CREATED_DIRS.iter() {
            if parent_path(dir.as_str()).as_str() == path {
                names.push(base_name(dir.as_str()));
            }
        }

        for file in CREATED_FILES.iter() {
            if parent_path(file.path.as_str()).as_str() == path {
                names.push(base_name(file.path.as_str()));
            }
        }
    }

    if names.is_empty() {
        names.push(String::from("."));
    }

    names
}

fn parent_path(path: &str) -> String {
    match path.rfind('/') {
        Some(0) | None => String::from("/"),
        Some(pos) => String::from(&path[..pos]),
    }
}

fn base_name(path: &str) -> String {
    match path.rfind('/') {
        Some(pos) => String::from(&path[pos + 1..]),
        None => String::from(path),
    }
}

fn join_path(base: &str, name: &str) -> String {
    if base == "/" {
        let mut out = String::from("/");
        out.push_str(name);
        out
    } else {
        let mut out = String::from(base);
        if !out.ends_with('/') {
            out.push('/');
        }
        out.push_str(name);
        out
    }
}

fn copy_user_cstr(ptr: usize, buf: &mut [u8]) -> Result<&str, isize> {
    if ptr == 0 || buf.is_empty() {
        return Err(err(EFAULT));
    }

    let mut len = 0usize;

    while len + 1 < buf.len() {
        let ok = crate::task::with_current_memory_set(|space| {
            space.copy_from_user(ptr + len, &mut buf[len..len + 1])
        });

        if !ok {
            return Err(err(EFAULT));
        }

        if buf[len] == 0 {
            return core::str::from_utf8(&buf[..len]).map_err(|_| err(EINVAL));
        }

        len += 1;
    }

    Err(err(EINVAL))
}

