pub fn sys_lseek(fd: usize, off: isize, whence: usize) -> isize {
    let task = crate::task::current();
    let Some(file) = task.user_file_mut(fd) else { return err(EBADF); };
    if file.is_dir { return err(EINVAL); }
    let new_off = match whence {
        0 => off as usize,                     // SEEK_SET
        1 => (file.offset as isize + off) as usize, // SEEK_CUR
        2 => (file.data.len() as isize + off) as usize, // SEEK_END
        _ => return err(EINVAL),
    };
    file.offset = new_off;
    new_off as isize
}

