pub fn sys_pread(fd: usize, buf: usize, len: usize, off: usize) -> isize {
    let task = crate::task::current();
    let Some(file) = task.user_file(fd) else { return err(EBADF); };
    if file.is_dir { return err(EINVAL); }
    if file.is_stdout { return err(EBADF); }
    if file.pipe_id.is_some() { return err(EINVAL); } // pipe support: use regular read instead
    let data = &file.data;
    if off >= data.len() { return 0; }
    let end = core::cmp::min(data.len(), off.saturating_add(len));
    let ok = crate::task::with_current_memory_set(|s| {
        s.copy_to_user_checked(buf, &data[off..end])
    });
    if ok { (end - off) as isize } else { err(EFAULT) }
}

pub fn sys_pwrite(fd: usize, buf: usize, len: usize, off: usize) -> isize {
    let task = crate::task::current();
    let Some(file) = task.user_file_mut(fd) else { return err(EBADF); };
    if file.is_dir || file.is_stdout { return err(EBADF); }
    if off.checked_add(len).map_or(true, |e| e > file.data.len()) {
        file.data.resize(off + len, 0);
    }
    let ok = crate::task::with_current_memory_set(|s| {
        s.copy_from_user(buf, &mut file.data[off..off+len])
    });
    if ok { len as isize } else { err(EFAULT) }
}

